#!/usr/bin/env python3
"""
=============================================================================
AUTOM-GAMIT + AUTOM-GLOBK/GLORG INTEGRATED LAUNCHER - V4 RINEX SAFE EDITION
=============================================================================
Based on the previous working V3, with station.info speed-up and a new per-day RINEX sandbox so multi-day processing does not fail after the first day cleanup., plus requested-epoch coordinate output in GLOBK/GLORG.

Major improvements:
- station.info is reduced using a selected IGS/reference sitelist where possible.
- station.info uses only selected local RINEX files; excluded stations are not used.
- sh_upd_stnfo output is saved to a log instead of flooding the terminal.
- RINEX header metadata is summarized in a clear station.info input table.
- station.info update result is verified before GAMIT continues.
- Repeated runs can skip sh_upd_stnfo if the exact selected RINEX set is unchanged.
- Existing APR/frame mismatch protection and GLOBK dashboard logic are preserved.
=============================================================================
"""
from __future__ import annotations

import os
import sys
import traceback

GAMIT_SOURCE = '#!/usr/bin/env python3\n"""\n=============================================================================\nAUTOM-GAMIT BEST V4 PER-DAY RINEX SAFE PROCESSOR - FINAL\n=============================================================================\n\nAll fixes applied:\n- Conditional tool checking (sh_get_rinex only when needed)\n- Support for .gz, .GZ, .Z, and long-name RINEX3\n- Safe .Z fallback (gzip -cd -> uncompress)\n- Lowercase normalization of local and global short-name RINEX filenames\n- Robust h-file station parser (uppercase, _GPS/_6PS/_5PS/_4PS)\n- Safer APR update line in process.defaults\n- Improved OTL grid resume logic\n- Reliable SOLVE Normal stop + h-file success check\n- Fast station.info easy manager + per-day clean RINEX sandbox\n- Correct GLOBK next-steps\n- Copy failure visible, IGS20 candidates reordered, APR conflict removal case-insensitive\n=============================================================================\n"""\n\nfrom __future__ import annotations\n\nimport gzip\nimport os\nimport re\nimport shlex\nimport signal\nimport subprocess\nimport sys\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import Dict, List, Tuple\n\n# =============================================================================\n# COLORS AND PRINT HELPERS\n# =============================================================================\nclass Colors:\n    RED = "\\033[91m"\n    GREEN = "\\033[92m"\n    YELLOW = "\\033[93m"\n    BLUE = "\\033[94m"\n    MAGENTA = "\\033[95m"\n    CYAN = "\\033[96m"\n    BOLD = "\\033[1m"\n    END = "\\033[0m"\n\ndef ctext(text: str, color: str) -> str:\n    return f"{color}{text}{Colors.END}"\n\ndef print_header(text: str) -> None:\n    print()\n    print(ctext("=" * 90, Colors.CYAN))\n    print(ctext(f"{text:^90}", Colors.CYAN + Colors.BOLD))\n    print(ctext("=" * 90, Colors.CYAN))\n\ndef print_info(text: str) -> None:\n    print(ctext(f"i  {text}", Colors.BLUE))\n\ndef print_success(text: str) -> None:\n    print(ctext(f"OK {text}", Colors.GREEN))\n\ndef print_warning(text: str) -> None:\n    print(ctext(f"WARNING {text}", Colors.YELLOW))\n\ndef print_error(text: str) -> None:\n    print(ctext(f"ERROR {text}", Colors.RED))\n\ndef print_progress(text: str) -> None:\n    print(ctext(f">> {text}", Colors.MAGENTA))\n\n# =============================================================================\n# INPUT HELPERS\n# =============================================================================\ndef ask_yes_no(question: str, default: str = "yes") -> bool:\n    default = default.lower().strip()\n    prompt = "[Y/n]" if default == "yes" else "[y/N]"\n    while True:\n        ans = input(ctext(f"{question} {prompt}: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            return default == "yes"\n        if ans in ("y", "yes"):\n            return True\n        if ans in ("n", "no"):\n            return False\n        print("Please answer yes or no.")\n\ndef ask_input(prompt: str, default: str = "") -> str:\n    if default != "":\n        ans = input(ctext(f"{prompt} [{default}]: ", Colors.CYAN)).strip()\n        return ans if ans != "" else default\n    return input(ctext(f"{prompt}: ", Colors.CYAN)).strip()\n\ndef ask_choice_index(question: str, options: List[str], default_index: int = 0) -> int:\n    print(ctext(question, Colors.CYAN))\n    for i, option in enumerate(options, 1):\n        marker = " [default]" if i - 1 == default_index else ""\n        print(f"  {ctext(str(i)+\'.\', Colors.YELLOW)} {option}{marker}")\n    while True:\n        ans = input(ctext(f"Enter choice (1-{len(options)}) [{default_index+1}]: ", Colors.CYAN)).strip()\n        if ans == "":\n            return default_index\n        if ans.isdigit() and 1 <= int(ans) <= len(options):\n            return int(ans) - 1\n        print(f"Please enter a number from 1 to {len(options)}.")\n\ndef ask_retry_continue_quit() -> str:\n    while True:\n        ans = input(ctext("Choose: r = retry, c = continue anyway, q = quit [q]: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            ans = "q"\n        if ans in ("r", "c", "q"):\n            return ans\n        print("Please enter r, c, or q.")\n\n# =============================================================================\n# BASIC HELPERS\n# =============================================================================\ndef q(value: object) -> str:\n    return shlex.quote(str(value))\n\ndef norm_sites(text: str) -> str:\n    return " ".join(text.lower().split())\n\ndef norm_doy(text: str) -> str:\n    return text.strip().zfill(3)\n\ndef station_list(text: str) -> List[str]:\n    return [s for s in norm_sites(text).split() if s]\n\ndef parse_rename_pairs(text: str) -> List[Tuple[str, str]]:\n    pairs: List[Tuple[str, str]] = []\n    for item in norm_sites(text).split():\n        if ":" not in item:\n            continue\n        old, new = item.split(":", 1)\n        if old and new:\n            pairs.append((old, new))\n    return pairs\n\ndef validate_station_code(site: str) -> bool:\n    return len(site) == 4 and site == site.lower() and site.isalnum()\n\n# =============================================================================\n# Path Normalizer\n# =============================================================================\ndef normalize_input_path(text: str) -> str:\n    text = text.strip().strip(\'"\').strip("\'")\n    if text.startswith("home/"):\n        text = "/" + text\n    return str(Path(os.path.expandvars(text)).expanduser())\n\n\ndef apr_family_from_name(apr_file: str) -> str:\n    """Return IGS20, IGS14, or ITRF08 from APR filename."""\n    name = Path(apr_file).name.lower()\n    if any(tok in name for tok in ["igs20", "igb20", "igc20", "itrf20"]):\n        return "IGS20"\n    if any(tok in name for tok in ["igs14", "igb14", "itrf14", "all_pbo_igs14", "all_pbo_nam14"]):\n        return "IGS14"\n    if any(tok in name for tok in ["igs08", "igb08", "itrf08", "all_pbo_igs08", "all_pbo_nam08"]):\n        return "ITRF08"\n    return "UNKNOWN"\n\n\ndef apr_matches_frame_name(ref_frame: str, apr_file: str) -> bool:\n    fam = apr_family_from_name(apr_file)\n    return fam == ref_frame\n\ndef validate_settings(settings: Dict[str, str]) -> bool:\n    errors: List[str] = []\n    year = settings["YEAR"]\n    yy = settings["YY"]\n    if not (year.isdigit() and len(year) == 4):\n        errors.append("YEAR must be 4 digits")\n    if not (yy.isdigit() and len(yy) == 2):\n        errors.append("YY must be 2 digits")\n    if year[-2:] != yy:\n        errors.append("YEAR and YY do not match")\n    expt = settings["EXPT"]\n    if not (len(expt) == 4 and expt.isalnum()):\n        errors.append("EXPT must be exactly 4 alphanumeric characters")\n    try:\n        s = int(settings["START_DOY"])\n        n = int(settings["NDAYS"])\n        if s < 1 or s > 366:\n            errors.append("START_DOY must be between 001 and 366")\n        if n < 1:\n            errors.append("NDAYS must be at least 1")\n        if s + n - 1 > 366:\n            errors.append("START_DOY + NDAYS exceeds 366")\n    except ValueError:\n        errors.append("START_DOY and NDAYS must be numeric")\n    for key in ["LOCAL_SITES", "IGS_SITES", "EXCLUDE_SITES"]:\n        for site in station_list(settings.get(key, "")):\n            if not validate_station_code(site):\n                errors.append(f"{key} has invalid station code: {site}")\n    local = set(station_list(settings["LOCAL_SITES"]))\n    igs = set(station_list(settings["IGS_SITES"]))\n    overlap = local & igs\n    if overlap:\n        errors.append("Station appears in both LOCAL_SITES and IGS_SITES: " + " ".join(sorted(overlap)))\n    for old, new in parse_rename_pairs(settings.get("RENAME_PAIRS", "")):\n        if not validate_station_code(old) or not validate_station_code(new):\n            errors.append(f"Invalid rename pair: {old}:{new}")\n        if old == new:\n            errors.append(f"Invalid rename pair, old and new same: {old}:{new}")\n        if new in igs:\n            errors.append(f"New station name conflicts with IGS list: {new}")\n    apr_file = settings.get("APR_FILE", "")\n    if not apr_file.endswith(".apr"):\n        errors.append("APR_FILE should end with .apr")\n    if "/" in apr_file:\n        errors.append("APR_FILE should be file name only")\n    if apr_file and not (Path.home() / "gg" / "tables" / apr_file).is_file():\n        errors.append(f"APR file not found in ~/gg/tables/: {apr_file}")\n    ref_frame = settings.get("REF_FRAME", "")\n    if apr_file and ref_frame and not apr_matches_frame_name(ref_frame, apr_file):\n        errors.append(f"APR file/frame mismatch: REF_FRAME={ref_frame}, APR_FILE={apr_file}. Choose matching APR family.")\n    custom = settings.get("CUSTOM_APR_FILE", "")\n    if not custom.endswith(".apr"):\n        errors.append("CUSTOM_APR_FILE should end with .apr")\n    if "/" in custom:\n        errors.append("CUSTOM_APR_FILE should be file name only")\n    if apr_file == custom:\n        errors.append("APR_FILE and CUSTOM_APR_FILE must not be same")\n    if settings.get("NOFTP_FLAG", "") not in ("", "-noftp"):\n        errors.append(\'NOFTP_FLAG must be blank or "-noftp"\')\n    for key in ["FRESH_START", "DOWNLOAD_GLOBAL_RINEX", "STRICT_NOFTP_CHECK", "RENAME_SITE"]:\n        if settings.get(key, "NO") not in ("YES", "NO"):\n            errors.append(f"{key} must be YES or NO")\n    if errors:\n        print_header("SETTING ERRORS")\n        for e in errors:\n            print_error(e)\n        return False\n    return True\n\n# =============================================================================\n# RINEX SCAN AND METADATA - Supports uppercase .GZ\n# =============================================================================\ndef strip_rinex_suffix(name: str, yy: str) -> str | None:\n    suffixes = [\n        f".{yy}o.gz", f".{yy}o.GZ", f".{yy}o.Z", f".{yy}o",\n        f".{yy}d.gz", f".{yy}d.GZ", f".{yy}d.Z", f".{yy}d",\n    ]\n    for suf in suffixes:\n        if name.endswith(suf):\n            return name[:-len(suf)]\n    return None\n\ndef scan_rinex_files(rinex_dir: str, yy: str) -> Tuple[List[str], Dict[str, dict]]:\n    path = Path(rinex_dir).expanduser()\n    if not path.is_dir():\n        return [], {}\n    files: List[Path] = []\n    for pat in [\n        f"*.{yy}o", f"*.{yy}o.gz", f"*.{yy}o.GZ", f"*.{yy}o.Z",\n        f"*.{yy}d", f"*.{yy}d.gz", f"*.{yy}d.GZ", f"*.{yy}d.Z",\n    ]:\n        files.extend(path.glob(pat))\n    station_info: Dict[str, dict] = {}\n    for f in sorted(files):\n        core = strip_rinex_suffix(f.name, yy)\n        if core is None or len(core) < 7:\n            continue\n        station = core[:4].lower()\n        doy = core[4:7]\n        if not validate_station_code(station):\n            continue\n        station_info.setdefault(station, {"files": [], "doys": set(), "sample_file": None})\n        station_info[station]["files"].append(str(f))\n        station_info[station]["doys"].add(doy)\n        if station_info[station]["sample_file"] is None or f.name.endswith(f".{yy}o"):\n            station_info[station]["sample_file"] = str(f)\n    for st in station_info:\n        station_info[st]["doy_count"] = len(station_info[st]["doys"])\n    return sorted(station_info.keys()), station_info\n\ndef open_text_maybe_gzip(file_path: str):\n    if file_path.endswith(".gz") or file_path.endswith(".GZ"):\n        return gzip.open(file_path, "rt", errors="ignore")\n    return open(file_path, "r", errors="ignore")\n\nRINEX_METADATA_CACHE: Dict[Tuple[str, int, int], Dict[str, object]] = {}\n\ndef read_rinex_metadata(file_path: str) -> Dict[str, object]:\n    """Read RINEX metadata once per file and reuse it inside the same run."""\n    try:\n        p = Path(file_path)\n        st = p.stat()\n        cache_key = (str(p), int(st.st_mtime), int(st.st_size))\n        if cache_key in RINEX_METADATA_CACHE:\n            return dict(RINEX_METADATA_CACHE[cache_key])\n    except Exception:\n        cache_key = None\n\n    metadata: Dict[str, object] = {\n        "marker": "Unknown",\n        "receiver": "Unknown",\n        "antenna": "Unknown",\n        "ant_height": "Unknown",\n        "interval": "Unknown",\n        "num_epochs": 0,\n        "approx_xyz": None,\n        "first_epoch": None,\n        "last_epoch": None,\n        "data_complete": False,\n        "readable": False,\n    }\n    if re.search(r"\\.\\d\\dd(\\.gz|\\.GZ|\\.Z)?$", file_path):\n        metadata["marker"] = "Hatanaka file - will convert later"\n        if cache_key is not None:\n            RINEX_METADATA_CACHE[cache_key] = dict(metadata)\n        return metadata\n    if file_path.endswith(".Z"):\n        metadata["marker"] = "Compressed .Z file - will uncompress later"\n        if cache_key is not None:\n            RINEX_METADATA_CACHE[cache_key] = dict(metadata)\n        return metadata\n    try:\n        with open_text_maybe_gzip(file_path) as f:\n            in_header = True\n            for line in f:\n                if in_header:\n                    if "MARKER NAME" in line:\n                        metadata["marker"] = line[:60].strip()\n                    elif "REC # / TYPE / VERS" in line:\n                        metadata["receiver"] = line[:60].strip()\n                    elif "ANT # / TYPE" in line:\n                        metadata["antenna"] = line[:60].strip()\n                    elif "ANTENNA: DELTA H/E/N" in line:\n                        parts = line[:60].split()\n                        if parts:\n                            metadata["ant_height"] = parts[0]\n                    elif "INTERVAL" in line:\n                        metadata["interval"] = line[:20].strip()\n                    elif "APPROX POSITION XYZ" in line:\n                        parts = line[:60].split()\n                        if len(parts) >= 3:\n                            metadata["approx_xyz"] = parts[:3]\n                    elif "END OF HEADER" in line:\n                        in_header = False\n                    continue\n                m3 = re.match(r"^>\\s*(\\d{4})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2}(?:\\.\\d+)?)", line)\n                m2 = re.match(r"\\s*(\\d{2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2}(?:\\.\\d+)?)", line)\n                if m3:\n                    y, mo, dd, hh, mi, _ss = m3.groups()\n                    epoch = f"{int(y):04d}-{int(mo):02d}-{int(dd):02d} {int(hh):02d}:{int(mi):02d}"\n                elif m2:\n                    yy2, mo, dd, hh, mi, _ss = m2.groups()\n                    epoch = f"{2000+int(yy2):04d}-{int(mo):02d}-{int(dd):02d} {int(hh):02d}:{int(mi):02d}"\n                else:\n                    continue\n                metadata["num_epochs"] = int(metadata["num_epochs"]) + 1\n                if metadata["first_epoch"] is None:\n                    metadata["first_epoch"] = epoch\n                metadata["last_epoch"] = epoch\n        metadata["readable"] = True\n        metadata["data_complete"] = int(metadata["num_epochs"]) >= 2500\n    except Exception as e:\n        metadata["marker"] = f"Could not read: {e}"\n    if cache_key is not None:\n        RINEX_METADATA_CACHE[cache_key] = dict(metadata)\n    return metadata\n\ndef show_station_summary(station_info: Dict[str, dict]) -> None:\n    print_header("STATION DATA SUMMARY")\n    print(f"{\'Station\':<8} {\'Files\':>5} {\'DOYs\':>5} {\'Epochs(sample)\':>15} {\'Quality\':>10} {\'First epoch\':<18} {\'Last epoch\':<18} {\'Receiver\':<25}")\n    print(ctext("-" * 115, Colors.CYAN))\n    for station in sorted(station_info):\n        info = station_info[station]\n        sample = info.get("sample_file")\n        md = read_rinex_metadata(sample) if sample else {}\n        epochs = md.get("num_epochs", 0)\n        quality = "OK" if md.get("data_complete") else "CHECK"\n        color = Colors.GREEN if quality == "OK" else Colors.YELLOW\n        first = str(md.get("first_epoch") or "N/A")[:16]\n        last = str(md.get("last_epoch") or "N/A")[:16]\n        receiver = str(md.get("receiver") or "Unknown")[:24]\n        print(f"{station:<8} {len(info[\'files\']):>5} {info[\'doy_count\']:>5} {epochs:>15} {ctext(f\'{quality:>10}\', color)} {first:<18} {last:<18} {receiver:<25}")\n    print(ctext("-" * 115, Colors.CYAN))\n    print_success(f"Total stations found: {len(station_info)}")\n\ndef show_station_details(station: str, station_info: Dict[str, dict]) -> None:\n    station = station.lower().strip()\n    if station not in station_info:\n        print_warning(f"Station not found: {station}")\n        return\n    info = station_info[station]\n    print_header(f"DETAILS FOR {station.upper()}")\n    for f in info["files"]:\n        md = read_rinex_metadata(f)\n        print(f"File       : {Path(f).name}")\n        print(f"Marker     : {md.get(\'marker\')}")\n        print(f"Receiver   : {md.get(\'receiver\')}")\n        print(f"Antenna    : {md.get(\'antenna\')}")\n        print(f"Interval   : {md.get(\'interval\')}")\n        print(f"Epochs     : {md.get(\'num_epochs\')}")\n        print(f"First/Last : {md.get(\'first_epoch\')}  ->  {md.get(\'last_epoch\')}")\n        print(f"Approx XYZ : {md.get(\'approx_xyz\')}")\n        print("-" * 80)\n\n# =============================================================================\n# APR HELPERS - Expanded candidates for all frames\n# =============================================================================\nAPR_CANDIDATES_BY_FRAME = {\n    "IGS20": [\n        "igb20_comb.apr",   # more common choice, placed first\n        "igs20_comb.apr",\n        "igs20.apr",\n        "igb20.apr",\n        "igc20.apr",\n        "itrf20f.apr",\n        "itrf20m.apr",\n        "itrf20u23f.apr",\n        "itrf20u23m.apr",\n        "itrf20u24f.apr",\n        "itrf20u24m.apr",\n    ],\n    "IGS14": [\n        "igs14_comb.apr",\n        "igb14_comb.apr",\n        "igb14.apr",\n        "itrf14.apr",\n        "itrf14_indi.apr",\n        "itrf14_noam.apr",\n        "itrf14_eura.apr",\n    ],\n    "ITRF08": [\n        "igs08_comb.apr",\n        "igb08_comb.apr",\n        "itrf08_comb.apr",\n        "igs08.apr",\n        "igb08.apr",\n        "itrf08.apr",\n        "All_PBO_igs08.apr",\n    ],\n}\n\ndef auto_select_apr_file(ref_frame: str) -> str:\n    tables_dir = Path.home() / "gg" / "tables"\n    for fname in APR_CANDIDATES_BY_FRAME.get(ref_frame, []):\n        if (tables_dir / fname).is_file():\n            return fname\n    cand = APR_CANDIDATES_BY_FRAME.get(ref_frame, [])\n    return cand[0] if cand else ""\n\ndef show_available_apr_files() -> List[str]:\n    tables_dir = Path.home() / "gg" / "tables"\n    apr_files = sorted(tables_dir.glob("*.apr")) if tables_dir.is_dir() else []\n    print_header("AVAILABLE APR FILES")\n    if not apr_files:\n        print_warning("No APR files found in ~/gg/tables/")\n        return []\n    for f in apr_files:\n        print(f"  {f.name}")\n    return [f.name for f in apr_files]\n\ndef apr_has_station(apr_file: str, site: str) -> bool:\n    path = Path.home() / "gg" / "tables" / apr_file\n    site_u = site.upper()\n    if not path.is_file():\n        return False\n    try:\n        with open(path, "r", errors="ignore") as f:\n            for line in f:\n                # Case-insensitive comparison\n                first = (line.split()[0] if line.split() else "").upper()\n                if first in (site_u, f"{site_u}_GPS"):\n                    return True\n    except Exception:\n        return False\n    return False\n\ndef normalize_conflict_sites(conflict_text: str) -> str:\n    out = []\n    for c in conflict_text.upper().split():\n        c = c.strip()\n        if len(c) == 4 and c.isalnum():\n            c = f"{c}_GPS"\n        elif c.endswith("_GPS") and len(c) == 8 and c[:4].isalnum():\n            pass\n        else:\n            clean = c.replace("_GPS", "")\n            if len(clean) == 4 and clean.isalnum():\n                c = f"{clean}_GPS"\n            else:\n                continue\n        if c not in out:\n            out.append(c)\n    return " ".join(out)\n\n# =============================================================================\n# Conditional tool checking (sh_get_rinex only when needed) - includes \'file\'\n# and optional \'uncompress\' if .Z files present\n# =============================================================================\ndef get_check_tools_step() -> str:\n    return r\'\'\'\necho "Checking required commands..."\nmissing=0\nfor cmd in sh_gamit sh_setup sh_upd_stnfo curl gzip gunzip awk sed date python3 file\ndo\n  if command -v "$cmd" >/dev/null 2>&1; then\n    echo "[OK] $cmd found at $(command -v $cmd)"\n  else\n    echo "[MISSING] $cmd"\n    missing=1\n  fi\ndone\n\n# Optional: check uncompress if .Z files exist\nif find "$SOURCE_RINEX_DIR" -maxdepth 1 \\( -name "*.${YY}o.Z" -o -name "*.${YY}d.Z" \\) | grep -q .; then\n  if command -v uncompress >/dev/null 2>&1; then\n    echo "[OK] uncompress found at $(command -v uncompress)"\n  else\n    echo "[WARNING] uncompress not found; gzip -cd fallback will be used for .Z files"\n  fi\nfi\n\nif [ "$DOWNLOAD_GLOBAL_RINEX" = "YES" ] && [ "$NOFTP_FLAG" != "-noftp" ]; then\n  if command -v sh_get_rinex >/dev/null 2>&1; then\n    echo "[OK] sh_get_rinex found at $(command -v sh_get_rinex)"\n  else\n    echo "[MISSING] sh_get_rinex is needed for automatic IGS RINEX download"\n    missing=1\n  fi\nelse\n  echo "[INFO] sh_get_rinex not required for this run mode"\nfi\n\nif find "$SOURCE_RINEX_DIR" -maxdepth 1 \\( -name "*.${YY}d" -o -name "*.${YY}d.gz" -o -name "*.${YY}d.GZ" -o -name "*.${YY}d.Z" \\) | grep -q .; then\n  if command -v crx2rnx >/dev/null 2>&1; then\n    echo "[OK] crx2rnx found at $(command -v crx2rnx)"\n  else\n    echo "[MISSING] crx2rnx is needed because local Hatanaka files were found"\n    missing=1\n  fi\nfi\n\nif [ "$DOWNLOAD_GLOBAL_RINEX" = "YES" ]; then\n  if command -v crx2rnx >/dev/null 2>&1; then\n    echo "[OK] crx2rnx found at $(command -v crx2rnx)"\n  else\n    echo "[MISSING] crx2rnx may be needed if downloaded IGS files are Hatanaka compressed"\n    missing=1\n  fi\nfi\n\nif [ "$missing" -eq 1 ]; then\n  echo "Missing required tools. Check GAMIT/GLOBK PATH in ~/.bashrc and run: source ~/.bashrc"\n  exit 1\nfi\necho "All required tools are available for this run mode."\n\'\'\'\n\ndef get_auth_step() -> str:\n    return r\'\'\'\necho "Checking Earthdata/CDDIS authentication..."\nif [ -f "$HOME/.netrc" ]; then\n  chmod 600 "$HOME/.netrc"\n  echo "[OK] .netrc exists and permission set to 600"\n  echo "Machine entries:"\n  awk \'{for(i=1;i<=NF;i++) if($i=="machine") print "  "$(i+1)}\' "$HOME/.netrc" 2>/dev/null || true\nelse\n  echo "[WARNING] ~/.netrc not found. Downloads may fail."\n  if [ "$NOFTP_FLAG" != "-noftp" ]; then\n    echo "NOFTP_FLAG is blank, so downloads are expected. Please create ~/.netrc first."\n    exit 1\n  fi\nfi\ntouch "$HOME/.urs_cookies"\nchmod 600 "$HOME/.urs_cookies"\necho "[OK] .urs_cookies ready"\nls -l "$HOME/.urs_cookies"\n\'\'\'\n\ndef get_create_project_step() -> str:\n    return r\'\'\'\necho "Creating/preparing project folder..."\ncd "$HOME" || exit 1\nif [ "$FRESH_START" = "YES" ] && [ -d "$PROJECT" ]; then\n  backup="${PROJECT}_old_$(date +%Y%m%d_%H%M%S)"\n  mv "$PROJECT" "$backup" || exit 1\n  echo "Existing project backed up as: $backup"\nfi\nmkdir -p "$PROJECT" || exit 1\ncd "$PROJECT" || exit 1\nmkdir -p rinex brdc igs ionex raw mkrinex control\necho "Project ready: $(pwd)"\nls -ld rinex brdc igs ionex raw mkrinex control\n\'\'\'\n\n# =============================================================================\n# FIXED: get_copy_rinex_step - safe .Z fallback + lowercase normalization\n# =============================================================================\ndef get_copy_rinex_step() -> str:\n    return r\'\'\'\necho "Copying local RINEX files from: $SOURCE_RINEX_DIR"\ncd "$HOME/$PROJECT" || exit 1\n\nif [ ! -d "$SOURCE_RINEX_DIR" ]; then\n  echo "Source RINEX directory not found: $SOURCE_RINEX_DIR"\n  exit 1\nfi\n\nshopt -s nullglob\nfiles=(\n  "$SOURCE_RINEX_DIR"/*.${YY}o\n  "$SOURCE_RINEX_DIR"/*.${YY}o.gz\n  "$SOURCE_RINEX_DIR"/*.${YY}o.GZ\n  "$SOURCE_RINEX_DIR"/*.${YY}o.Z\n  "$SOURCE_RINEX_DIR"/*.${YY}d\n  "$SOURCE_RINEX_DIR"/*.${YY}d.gz\n  "$SOURCE_RINEX_DIR"/*.${YY}d.GZ\n  "$SOURCE_RINEX_DIR"/*.${YY}d.Z\n)\n\nif [ "${#files[@]}" -eq 0 ]; then\n  echo "No short-name .${YY}o/.${YY}d files found in source folder."\n  echo "This processor expects short-name local RINEX, for example hyde0910.${YY}o or hyde0910.${YY}d.gz."\n  exit 1\nfi\n\n# Copy with error exit\ncp -f "${files[@]}" rinex/ || exit 1\n\ncd rinex || exit 1\n\n# Normalize first 4 characters of filenames to lowercase (case-insensitive safety)\necho "Normalizing first 4 characters of local RINEX filenames to lowercase..."\npython3 - << \'PY\'\nfrom pathlib import Path\nimport os\n\nyy = os.environ["YY"]\nsuffixes = [\n    f".{yy}o.gz", f".{yy}o.GZ", f".{yy}o.Z", f".{yy}o",\n    f".{yy}d.gz", f".{yy}d.GZ", f".{yy}d.Z", f".{yy}d",\n]\n\nfor p in sorted(Path(".").iterdir()):\n    if not p.is_file():\n        continue\n    name = p.name\n    matched = False\n    for suf in suffixes:\n        if name.endswith(suf) and len(name) >= 7 + len(suf):\n            matched = True\n            break\n    if not matched:\n        continue\n    new_name = name[:4].lower() + name[4:]\n    if new_name == name:\n        continue\n    target = p.with_name(new_name)\n    if target.exists():\n        print(f"ERROR: Cannot rename {name} -> {new_name}; target already exists")\n        raise SystemExit(1)\n    print(f"  {name} -> {new_name}")\n    p.rename(target)\nPY\n\n# Remove invalid local compressed files\necho "Checking compressed local RINEX files before uncompressing..."\nfor f in *.${YY}o.gz *.${YY}o.GZ *.${YY}o.Z *.${YY}d.gz *.${YY}d.GZ *.${YY}d.Z; do\n  [ -f "$f" ] || continue\n  if ! gzip -t "$f" 2>/dev/null && ! file "$f" | grep -q "compress\'d data"; then\n    echo "  Invalid/incomplete compressed file: $f"\n    echo "  Remove or re-download this file before processing."\n    exit 1\n  fi\ndone\n\n# Safe uncompression for observation files\necho "Uncompressing observation files if needed..."\nfor f in *.${YY}o.gz *.${YY}o.GZ *.${YY}o.Z; do\n  [ -f "$f" ] || continue\n  echo "  Uncompressing: $f"\n  if [[ "$f" == *.Z ]]; then\n    out="${f%.Z}"\n    gzip -cd "$f" > "$out" 2>/dev/null || uncompress -c "$f" > "$out" || exit 1\n  else\n    gunzip -k -f "$f" || exit 1\n  fi\ndone\n\n# Local Hatanaka conversion with fallback for .Z\necho "Converting local Hatanaka files if present..."\nfor f in *.${YY}d.gz *.${YY}d.GZ *.${YY}d.Z; do\n  [ -f "$f" ] || continue\n  dfile="${f%.*}"\n  echo "  Uncompressing Hatanaka: $f"\n  if [[ "$f" == *.Z ]]; then\n    gzip -cd "$f" > "$dfile" 2>/dev/null || uncompress -c "$f" > "$dfile" || exit 1\n  else\n    gunzip -c "$f" > "$dfile" || exit 1\n  fi\ndone\n\nfor f in *.${YY}d; do\n  [ -f "$f" ] || continue\n  if ! command -v crx2rnx >/dev/null 2>&1; then\n    echo "crx2rnx not found; cannot convert $f"\n    exit 1\n  fi\n  echo "  crx2rnx: $f"\n  crx2rnx "$f" || exit 1\ndone\n\ncd ..\n\necho "Active uncompressed RINEX count:"\nls rinex/*.${YY}o 2>/dev/null | wc -l\n\necho "Day-wise count for selected range:"\nEND_DOY=$((10#$START_DOY + NDAYS - 1))\nfor n in $(seq $((10#$START_DOY)) $END_DOY); do\n  doy=$(printf "%03d" "$n")\n  count=$(ls rinex/*${doy}0.${YY}o 2>/dev/null | wc -l)\n  echo "  DOY $doy : $count files"\ndone\n\'\'\'\n\ndef get_exclude_step() -> str:\n    return r\'\'\'\necho "Excluding source stations: $EXCLUDE_SITES"\ncd "$HOME/$PROJECT" || exit 1\nif [ -z "$EXCLUDE_SITES" ]; then\n  echo "No stations selected for exclusion."\n  exit 0\nfi\nfor ex in $EXCLUDE_SITES; do\n  mkdir -p "rinex_excluded_${ex}"\n  moved=0\n  for f in rinex/${ex}*.${YY}o rinex/${ex}*.${YY}o.gz rinex/${ex}*.${YY}o.GZ rinex/${ex}*.${YY}o.Z rinex/${ex}*.${YY}d rinex/${ex}*.${YY}d.gz rinex/${ex}*.${YY}d.GZ rinex/${ex}*.${YY}d.Z; do\n    [ -e "$f" ] || continue\n    mv "$f" "rinex_excluded_${ex}/"\n    moved=1\n  done\n  if [ "$moved" -eq 1 ]; then\n    echo "  Excluded: $ex"\n  else\n    echo "  No files found for: $ex"\n  fi\ndone\n\'\'\'\n\ndef get_rename_step() -> str:\n    return r\'\'\'\necho "Renaming stations..."\ncd "$HOME/$PROJECT" || exit 1\nif [ "$RENAME_SITE" != "YES" ] || [ -z "$RENAME_PAIRS" ]; then\n  echo "No rename requested."\n  exit 0\nfi\nfor pair in $RENAME_PAIRS; do\n  old=$(echo "$pair" | cut -d: -f1)\n  new=$(echo "$pair" | cut -d: -f2)\n  echo "------------------------------------------------------------"\n  echo "Rename: $old -> $new"\n  echo "------------------------------------------------------------"\n  if [ -z "$old" ] || [ -z "$new" ] || [ "$old" = "$new" ]; then\n    echo "Invalid rename pair: $pair"\n    exit 1\n  fi\n  mkdir -p "rinex_excluded_${old}_oldcode" "rinex_existing_${new}_before_rename"\n  NEWU=$(echo "$new" | tr \'[:lower:]\' \'[:upper:]\')\n  for f in rinex/${old}*.${YY}o; do\n    [ -f "$f" ] || continue\n    base=$(basename "$f")\n    newbase="${new}${base#$old}"\n    target="rinex/$newbase"\n    if [ -f "$target" ]; then\n      echo "  Target exists, backing up: $target"\n      mv "$target" "rinex_existing_${new}_before_rename/"\n    fi\n    echo "  Creating renamed RINEX: $target"\n    awk -v newmarker="$NEWU" \'\n      /MARKER NAME/ { printf "%-60s%-20s\\n", newmarker, "MARKER NAME"; next }\n      {print}\n    \' "$f" > "$target" || exit 1\n  done\n  mv rinex/${old}*.${YY}o "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}o.gz "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}o.GZ "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}o.Z "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d.gz "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d.GZ "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d.Z "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  echo "  Rename completed: $old -> $new"\ndone\necho "Final renamed files:"\nfor pair in $RENAME_PAIRS; do\n  new=$(echo "$pair" | cut -d: -f2)\n  ls -lh rinex/${new}*.${YY}o 2>/dev/null || true\ndone\n\'\'\'\n\ndef get_sh_setup_step() -> str:\n    return r\'\'\'\necho "Running sh_setup..."\ncd "$HOME/$PROJECT" || exit 1\nsh_setup -yr "$YEAR"\nrc=$?\nif [ "$rc" -ne 0 ]; then\n  echo "sh_setup failed with return code $rc"\n  exit "$rc"\nfi\nif [ ! -d tables ]; then\n  echo "tables directory was not created"\n  exit 1\nfi\necho "Tables created. Key files:"\nls -lh tables/station.info tables/sestbl. tables/sittbl. tables/autcln.cmd tables/process.defaults tables/sites.defaults tables/lfile. 2>/dev/null || true\n\'\'\'\n\n# =============================================================================\n# FIXED: get_apr_step - Safer APR update line and case-insensitive conflict removal\n# =============================================================================\ndef get_apr_step() -> str:\n    return r\'\'\'\necho "Configuring APR file..."\necho "REF_FRAME       : $REF_FRAME"\necho "APR_FILE        : $APR_FILE"\necho "CUSTOM_APR_FILE : $CUSTOM_APR_FILE"\necho "CONFLICT_SITE   : $CONFLICT_SITE"\n\ncd "$HOME/$PROJECT/tables" || exit 1\n\nif [ ! -f "$HOME/gg/tables/$APR_FILE" ]; then\n  echo "APR file not found: $HOME/gg/tables/$APR_FILE"\n  echo "Available APR files:"\n  ls "$HOME"/gg/tables/*apr 2>/dev/null || true\n  exit 1\nfi\n\ncp "$HOME/gg/tables/$APR_FILE" . || exit 1\ncp process.defaults process.defaults.before_apr_change 2>/dev/null || true\ncp "$APR_FILE" "$CUSTOM_APR_FILE" || exit 1\n\nif [ -n "$CONFLICT_SITE" ]; then\n  for bad in $CONFLICT_SITE; do\n    bad4=$(echo "$bad" | sed \'s/_GPS$//\')\n    echo "Removing APR conflict if present: $bad or $bad4"\n    # Case-insensitive removal\n    awk -v bad="$bad" -v bad4="$bad4" \'toupper($1) != toupper(bad) && toupper($1) != toupper(bad4) {print}\' "$CUSTOM_APR_FILE" > "${CUSTOM_APR_FILE}.tmp"\n    mv "${CUSTOM_APR_FILE}.tmp" "$CUSTOM_APR_FILE"\n  done\nfi\n\n# Safer APR line update\nif grep -Eq \'^[[:space:]]*set[[:space:]]+aprf[[:space:]]*=\' process.defaults; then\n  sed -i -E "s|^[[:space:]]*set[[:space:]]+aprf[[:space:]]*=.*|set aprf = $CUSTOM_APR_FILE|" process.defaults\nelse\n  echo "set aprf = $CUSTOM_APR_FILE" >> process.defaults\nfi\n\necho "Final process.defaults APR line:"\ngrep -n "aprf" process.defaults || true\necho "APR setup complete."\n\'\'\'\n\ndef get_sites_defaults_step() -> str:\n    return r\'\'\'\necho "Creating sites.defaults..."\ncd "$HOME/$PROJECT/tables" || exit 1\ncp sites.defaults sites.defaults.before_auto_create 2>/dev/null || true\n{\n  echo "# IGS/reference stations"\n  for s in $IGS_SITES; do\n    echo " ${s}_gps $EXPT ftprnx"\n  done\n  echo ""\n  echo "# Local CORS stations"\n  for s in $LOCAL_SITES; do\n    echo " ${s}_gps $EXPT localrx"\n  done\n} > sites.defaults\ncat sites.defaults\necho "IGS count   : $(grep -c \'ftprnx\' sites.defaults)"\necho "Local count : $(grep -c \'localrx\' sites.defaults)"\n\ncd "$HOME/$PROJECT" || exit 1\nmissing=0\nfor s in $LOCAL_SITES; do\n  for n in $(seq $((10#$START_DOY)) $END_DOY); do\n    doy=$(printf "%03d" "$n")\n    f="rinex/${s}${doy}0.${YY}o"\n    if [ -f "$f" ]; then\n      echo "[OK] $f"\n    else\n      echo "[MISSING] $f"\n      missing=1\n    fi\n  done\ndone\nif [ "$missing" -eq 1 ]; then\n  echo "Some local RINEX files are missing. Fix LOCAL_SITES/rename/exclude settings."\n  exit 1\nfi\n\'\'\'\n\n# =============================================================================\n# FIXED: get_lfile_step - Robust conflict removal\n# =============================================================================\ndef get_lfile_step() -> str:\n    return r\'\'\'\necho "Updating lfile. from local RINEX APPROX POSITION XYZ..."\ncd "$HOME/$PROJECT" || exit 1\ncd tables || exit 1\ncp lfile. lfile.before_local_update 2>/dev/null || true\nfor s in $LOCAL_SITES; do\n  U=$(echo "$s" | tr \'[:lower:]\' \'[:upper:]\')\n  grep -v "^ *${U}_GPS" lfile. > lfile.tmp\n  mv lfile.tmp lfile.\ndone\nif [ -n "$CONFLICT_SITE" ]; then\n  for bad in $CONFLICT_SITE; do\n    bad4=$(echo "$bad" | sed \'s/_GPS$//\')\n    grep -v -E "^ *(${bad}|${bad4})( |$)" lfile. > lfile.tmp\n    mv lfile.tmp lfile.\n  done\nfi\ncd "$HOME/$PROJECT" || exit 1\npython3 - << \'PY\'\nfrom pathlib import Path\nimport os\nproject = Path.home() / os.environ["PROJECT"]\nrinex = project / "rinex"\nlfile = project / "tables" / "lfile."\nsites = os.environ["LOCAL_SITES"].split()\nyy = os.environ["YY"]\nyear = int(os.environ["YEAR"])\nstart_doy = int(os.environ["START_DOY"])\nepoch = year + (start_doy - 1) / 365.25\nadded = 0\nwith open(lfile, "a") as out:\n    for site in sites:\n        files = sorted(rinex.glob(f"{site}*.{yy}o"))\n        if not files:\n            print(f"[WARNING] No RINEX found for {site}")\n            continue\n        f = files[0]\n        xyz = None\n        with open(f, "r", errors="ignore") as fp:\n            for line in fp:\n                if "APPROX POSITION XYZ" in line:\n                    parts = line[:60].split()\n                    if len(parts) >= 3:\n                        xyz = [float(parts[0]), float(parts[1]), float(parts[2])]\n                    break\n        if xyz is None:\n            print(f"[WARNING] No APPROX POSITION XYZ in {f.name}")\n            continue\n        U = site.upper()\n        out.write(\n            f"{U}_GPS {xyz[0]:16.5f} {xyz[1]:16.5f} {xyz[2]:16.5f}"\n            f"     0.00000   0.00000   0.00000    {epoch:.4f}"\n            f" ! Local CORS from RINEX header\\n"\n        )\n        print(f"Added {U}_GPS from {f.name}: {xyz}")\n        added += 1\nif added == 0:\n    print("ERROR: No local lfile entries were added")\n    raise SystemExit(1)\nPY\necho "Final local lfile entries:"\ncd tables || exit 1\nfor s in $LOCAL_SITES; do\n  U=$(echo "$s" | tr \'[:lower:]\' \'[:upper:]\')\n  grep "^ *${U}_GPS" lfile. || echo "[WARNING] Missing lfile entry for $U"\ndone\n\'\'\'\n\ndef get_station_info_step() -> str:\n    return r\'\'\'\necho "STATION.INFO EASY MANAGER - fast, quiet, selected-files only"\ncd "$HOME/$PROJECT/tables" || exit 1\n\nREPORT="station_info_easy_report.txt"\nFILES_USED="station_info_files_used.txt"\nCMD_FILE="station_info_update_command.txt"\nUPDATE_LOG="station_info_update.log"\nREF_LOG="station_info_ref_filter.log"\nCACHE_FILE="station_info_easy_cache_key.txt"\nCACHE_NOW="station_info_easy_cache_key.current"\n\n: > "$REPORT"\n: > "$FILES_USED"\n: > "$CMD_FILE"\n: > "$UPDATE_LOG"\n: > "$REF_LOG"\n\n{\n  echo "STATION.INFO EASY MANAGER"\n  echo "Project     : $HOME/$PROJECT"\n  echo "Experiment  : $EXPT"\n  echo "Year/DOY    : $YEAR $START_DOY to $END_DOY"\n  echo "Local sites : $LOCAL_SITES"\n  echo "IGS sites   : $IGS_SITES"\n  echo "Conflict    : ${CONFLICT_SITE:-None}"\n  echo ""\n} >> "$REPORT"\n\n# 1. Create sitelist from selected IGS/reference stations.\necho "Creating tables/sitelist from selected IGS/reference sites..."\n: > sitelist\nfor s in $IGS_SITES; do\n  echo " $s" >> sitelist\ndone\n\necho "Selected reference station sitelist:" >> "$REPORT"\ncat sitelist >> "$REPORT"\necho "" >> "$REPORT"\n\n# 2. Build the exact selected local RINEX file list. Do not use ../rinex/*.YYo blindly.\nmissing=0\nfor s in $LOCAL_SITES; do\n  for n in $(seq $((10#$START_DOY)) $END_DOY); do\n    doy=$(printf "%03d" "$n")\n    f="../rinex/${s}${doy}0.${YY}o"\n    if [ -f "$f" ]; then\n      echo "$f" >> "$FILES_USED"\n    else\n      echo "[WARNING] Missing for station.info: $f" | tee -a "$REPORT"\n      missing=1\n    fi\n  done\ndone\n\nnfiles=$(wc -l < "$FILES_USED" | tr -d \' \')\necho "Number of selected local RINEX files for station.info: $nfiles"\necho "Number of selected local RINEX files: $nfiles" >> "$REPORT"\n\nif [ "$nfiles" -eq 0 ]; then\n  echo "No local RINEX files found for station.info" | tee -a "$REPORT"\n  exit 1\nfi\n\n# 3. RINEX header dashboard/report: marker, receiver, antenna, height, interval.\npython3 - << \'PYEASY1\'\nfrom pathlib import Path\nimport os, re, hashlib\n\nfiles_used = Path(\'station_info_files_used.txt\')\nreport = Path(\'station_info_easy_report.txt\')\ncache_now = Path(\'station_info_easy_cache_key.current\')\nlocal_sites = os.environ.get(\'LOCAL_SITES\',\'\').split()\nfiles = [Path(x.strip()) for x in files_used.read_text().splitlines() if x.strip()]\n\ndef read_header(path: Path):\n    md = {\'marker\':\'Unknown\', \'receiver\':\'Unknown\', \'antenna\':\'Unknown\', \'height\':\'Unknown\', \'interval\':\'Unknown\', \'approx\':\'NO\', \'epochs\':0}\n    try:\n        in_header = True\n        with open(path, \'r\', errors=\'ignore\') as f:\n            for line in f:\n                if in_header:\n                    if \'MARKER NAME\' in line:\n                        md[\'marker\'] = line[:60].strip()\n                    elif \'REC # / TYPE / VERS\' in line:\n                        md[\'receiver\'] = line[:60].strip()\n                    elif \'ANT # / TYPE\' in line:\n                        md[\'antenna\'] = line[:60].strip()\n                    elif \'ANTENNA: DELTA H/E/N\' in line:\n                        parts = line[:60].split()\n                        if parts: md[\'height\'] = parts[0]\n                    elif \'INTERVAL\' in line:\n                        md[\'interval\'] = line[:20].strip()\n                    elif \'APPROX POSITION XYZ\' in line:\n                        md[\'approx\'] = \'YES\'\n                    elif \'END OF HEADER\' in line:\n                        in_header = False\n                    continue\n                m3 = re.match(r\'^>\\s*\\d{4}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\', line)\n                m2 = re.match(r\'\\s*\\d{2}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\', line)\n                if m3 or m2:\n                    md[\'epochs\'] += 1\n    except Exception as e:\n        md[\'marker\'] = f\'Could not read: {e}\'\n    return md\n\nby_site = {s: [] for s in local_sites}\nfor f in files:\n    site = f.name[:4].lower()\n    if site in by_site:\n        by_site[site].append(f)\n\nlines = []\nlines.append(\'\\nSTATION.INFO INPUT CHECK\')\nlines.append(\'Station  Days  Marker  Receiver                 Antenna           Height   Intv   Epochs(min-max)  Status\')\nlines.append(\'-\'*115)\n\ncache_parts = []\nfor site in local_sites:\n    fs = sorted(by_site.get(site, []))\n    statuses = []\n    markers = []\n    receivers = []\n    antennas = []\n    heights = []\n    intervals = []\n    epochs = []\n    for f in fs:\n        st = f.stat()\n        cache_parts.append(f\'{f}:{st.st_size}:{int(st.st_mtime)}\')\n        md = read_header(f)\n        markers.append(md[\'marker\']); receivers.append(md[\'receiver\']); antennas.append(md[\'antenna\'])\n        heights.append(md[\'height\']); intervals.append(md[\'interval\']); epochs.append(int(md[\'epochs\']))\n        marker4 = str(md[\'marker\']).split()[0].upper()[:4]\n        if marker4 and marker4 != site.upper():\n            statuses.append(f\'MARKER {marker4}!={site.upper()}\')\n        if str(md[\'height\']).strip() in (\'0\', \'0.0\', \'0.0000\', \'0.00000\'):\n            statuses.append(\'CHECK_HEIGHT\')\n        if md[\'approx\'] != \'YES\':\n            statuses.append(\'NO_APPROX_XYZ\')\n    days = f\'{len(fs)}/{int(os.environ.get("NDAYS","0") or 0)}\'\n    marker = (markers[0] if markers else \'-\')[:8]\n    rec = (receivers[0] if receivers else \'-\')[:24]\n    ant = (antennas[0] if antennas else \'-\')[:16]\n    hgt = (heights[0] if heights else \'-\')[:8]\n    itv = (intervals[0] if intervals else \'-\')[:6]\n    ep = \'-\' if not epochs else f\'{min(epochs)}-{max(epochs)}\'\n    status = \'OK\' if not statuses else \',\'.join(sorted(set(statuses)))\n    lines.append(f\'{site.upper():8s} {days:5s} {marker:8s} {rec:24s} {ant:16s} {hgt:8s} {itv:6s} {ep:15s} {status}\')\nlines.append(\'-\'*115)\nwith open(report, \'a\') as out:\n    out.write(\'\\n\'.join(lines) + \'\\n\')\nprint(\'\\n\'.join(lines))\n\nkey_raw = \'\\n\'.join(cache_parts + [os.environ.get(\'LOCAL_SITES\',\'\'), os.environ.get(\'IGS_SITES\',\'\'), os.environ.get(\'CONFLICT_SITE\',\'\')])\ncache_now.write_text(hashlib.sha256(key_raw.encode()).hexdigest() + \'\\n\')\nPYEASY1\n\n# 4. Cache: if same selected files and station.info already contains all locals, skip sh_upd_stnfo.\nif [ -f "$CACHE_FILE" ] && cmp -s "$CACHE_FILE" "$CACHE_NOW"; then\n  if python3 - << \'PYEASY2\'\nfrom pathlib import Path\nimport os, re, sys\ntext = Path(\'station.info\').read_text(errors=\'ignore\').upper() if Path(\'station.info\').exists() else \'\'\nmissing=[]\nfor s in os.environ.get(\'LOCAL_SITES\',\'\').split():\n    u=s.upper()\n    if not re.search(r\'^\\s*\' + re.escape(u) + r\'(\\s|$)\', text, flags=re.M):\n        missing.append(u)\nif missing:\n    print(\'Missing in station.info despite cache:\', \' \'.join(missing))\n    sys.exit(1)\nsys.exit(0)\nPYEASY2\n  then\n    echo "[OK] station.info already up to date for this exact selected RINEX set. Skipping sh_upd_stnfo."\n    echo "station.info update skipped by cache." >> "$REPORT"\n    exit 0\n  fi\nfi\n\n# 5. Backup and make station.info smaller using selected IGS/reference sitelist.\ncp station.info station.info.before_easy_update_$(date +%Y%m%d_%H%M%S) 2>/dev/null || true\ncp station.info station.info.easy_original 2>/dev/null || true\n\necho "Reducing station.info to selected IGS/reference stations using sitelist..."\nrm -f station.info.new\nif sh_upd_stnfo -l sitelist > "$REF_LOG" 2>&1 && [ -s station.info.new ]; then\n  mv station.info.new station.info\n  echo "[OK] station.info reduced using sitelist."\n  echo "station.info reduced using sitelist." >> "$REPORT"\nelse\n  echo "[WARNING] Could not reduce station.info with sitelist. Keeping original station.info. See $REF_LOG"\n  [ -f station.info.easy_original ] && cp station.info.easy_original station.info\n  echo "station.info reduction skipped/fallback used." >> "$REPORT"\nfi\n\n# 6. Remove previous local/conflict/renamed entries before adding clean metadata.\npython3 - << \'PYEASY3\'\nfrom pathlib import Path\nimport os\nremove=set()\nfor s in os.environ.get(\'LOCAL_SITES\',\'\').split():\n    u=s.upper(); remove.add(u); remove.add(u+\'_GPS\')\nfor s in os.environ.get(\'CONFLICT_SITE\',\'\').split():\n    u=s.upper(); remove.add(u); remove.add(u.replace(\'_GPS\',\'\'))\nfor pair in os.environ.get(\'RENAME_PAIRS\',\'\').split():\n    if \':\' in pair:\n        old,new=pair.split(\':\',1)\n        for x in (old,new):\n            u=x.upper(); remove.add(u); remove.add(u+\'_GPS\')\np=Path(\'station.info\')\nif not p.exists():\n    raise SystemExit(\'station.info missing\')\nout=[]; removed=0\nfor line in p.read_text(errors=\'ignore\').splitlines(True):\n    parts=line.split()\n    first=parts[0].upper() if parts else \'\'\n    first4=first.replace(\'_GPS\',\'\')\n    if first in remove or first4 in remove:\n        removed += 1\n        continue\n    out.append(line)\np.write_text(\'\'.join(out), encoding=\'utf-8\', errors=\'ignore\')\nprint(f\'[OK] Removed {removed} old local/conflict station.info line(s).\')\nPYEASY3\n\n# 7. Run sh_upd_stnfo quietly on selected local RINEX only.\nmapfile -t RINEX_FILES < "$FILES_USED"\n{\n  echo "cd $HOME/$PROJECT/tables"\n  printf \'sh_upd_stnfo -files\'\n  for f in "${RINEX_FILES[@]}"; do printf \' %q\' "$f"; done\n  printf \'\\n\'\n} > "$CMD_FILE"\n\necho "Running sh_upd_stnfo quietly. Full output will be in: $PWD/$UPDATE_LOG"\nsh_upd_stnfo -files "${RINEX_FILES[@]}" > "$UPDATE_LOG" 2>&1\nrc=$?\nif [ "$rc" -ne 0 ]; then\n  echo "sh_upd_stnfo failed with code $rc. Last log lines:"\n  tail -80 "$UPDATE_LOG" || true\n  exit "$rc"\nfi\ncp "$CACHE_NOW" "$CACHE_FILE" 2>/dev/null || true\n\n# 8. Verify local stations and print only a short useful summary.\necho "station.info updated. Verification summary:"\npython3 - << \'PYEASY4\'\nfrom pathlib import Path\nimport os, re, sys\np=Path(\'station.info\')\ntext=p.read_text(errors=\'ignore\') if p.exists() else \'\'\nlines=text.splitlines()\nreport=Path(\'station_info_easy_report.txt\')\nsummary=[]; missing=[]\nsummary.append(\'\\nSTATION.INFO UPDATE RESULT\')\nsummary.append(\'Station  Entry  Status        Last station.info line\')\nsummary.append(\'-\'*110)\nfor s in os.environ.get(\'LOCAL_SITES\',\'\').split():\n    u=s.upper(); matches=[]\n    for line in lines:\n        parts=line.split()\n        if parts and parts[0].upper()==u:\n            matches.append(line)\n    if matches:\n        last=matches[-1]\n        status=\'OK\'\n        if re.search(r\'\\s0\\.0000+\\s\', last): status=\'CHECK_HEIGHT\'\n        summary.append(f\'{u:8s} FOUND  {status:12s} {last[:75]}\')\n    else:\n        missing.append(u)\n        summary.append(f\'{u:8s} MISSING ERROR        -\')\nsummary.append(\'-\'*110)\nprint(\'\\n\'.join(summary))\nwith open(report,\'a\') as f:\n    f.write(\'\\n\'.join(summary)+\'\\n\')\nif missing:\n    print(\'ERROR: Missing local stations in station.info:\', \' \'.join(missing))\n    sys.exit(1)\nPYEASY4\n\necho "[OK] station.info easy update completed."\necho "Reports saved:"\necho "  $PWD/$REPORT"\necho "  $PWD/$FILES_USED"\necho "  $PWD/$CMD_FILE"\necho "  $PWD/$UPDATE_LOG"\necho "NOTE: antenna height 0.0000 is acceptable only for demo. Correct it for final scientific results."\n\'\'\'\n\n# =============================================================================\n# FIXED: get_otl_step - Robust sestbl. update\n# =============================================================================\ndef get_otl_step() -> str:\n    return r\'\'\'\necho "Checking Ocean Tide Loading files..."\necho "This step is mandatory because sh_gamit fails with: Ocean loading requested no list or grid file"\n\nmkdir -p "$HOME/gg/GRIDS"\nOTL_GRID_MASTER="$HOME/gg/GRIDS/otl_FES2004.grid"\nOTL_GRID_MIN_BYTES=600000000\n\ncheck_big_readable_file() {\n  f="$1"\n  minbytes="$2"\n  label="$3"\n  if [ ! -r "$f" ]; then\n    echo "[MISSING] $label not readable: $f"\n    return 1\n  fi\n  bytes=$(wc -c < "$f" 2>/dev/null || echo 0)\n  echo "[INFO] $label size: $bytes bytes"\n  if [ "$bytes" -lt "$minbytes" ]; then\n    echo "[MISSING] $label too small/incomplete: $f"\n    return 1\n  fi\n  echo "[OK] $label readable and size looks valid: $f"\n  return 0\n}\n\ndownload_otl_grid() {\n  cd "$HOME/gg/GRIDS" || exit 1\n  echo "Downloading/resuming OTL grid: otl_FES2004.grid"\n  echo "This file is large, about 697 MB. It may take several minutes, but it is downloaded only once."\n\n  if [ -e otl_FES2004.grid ] || [ -L otl_FES2004.grid ]; then\n    bytes=$(wc -c < otl_FES2004.grid 2>/dev/null || echo 0)\n    if [ "$bytes" -eq 0 ]; then\n      echo "[WARNING] Removing zero-byte OTL grid"\n      rm -f otl_FES2004.grid\n    elif LC_ALL=C head -c 300 otl_FES2004.grid 2>/dev/null | grep -Eiq \'(<html|<!doctype|login|error|not found|forbidden|unauthorized)\'; then\n      echo "[WARNING] Existing OTL grid looks like HTML/error page, removing"\n      rm -f otl_FES2004.grid\n    elif [ "$bytes" -lt "$OTL_GRID_MIN_BYTES" ]; then\n      echo "[INFO] Keeping partial binary OTL grid for resume: $bytes bytes"\n    fi\n  fi\n\n  curl -k -f -L -C - \\\n    --connect-timeout 60 \\\n    --max-time 3600 \\\n    --speed-limit 100 --speed-time 180 \\\n    --retry 5 --retry-delay 10 --retry-connrefused \\\n    -o otl_FES2004.grid \\\n    https://chandler.mit.edu/ftp/GRIDS/otl_FES2004.grid\n}\n\nif ! check_big_readable_file "$OTL_GRID_MASTER" "$OTL_GRID_MIN_BYTES" "OTL grid"; then\n  if [ "$NOFTP_FLAG" = "-noftp" ]; then\n    echo "OTL grid missing/incomplete in -noftp mode."\n    echo "Expected: $OTL_GRID_MASTER"\n    exit 1\n  fi\n  download_otl_grid || true\n  if ! check_big_readable_file "$OTL_GRID_MASTER" "$OTL_GRID_MIN_BYTES" "OTL grid after download"; then\n    echo "[ERROR] OTL grid still missing/incomplete after download attempt."\n    echo "Manual command:"\n    echo "mkdir -p ~/gg/GRIDS && cd ~/gg/GRIDS"\n    echo "curl -k -f -L -C - --connect-timeout 60 --max-time 3600 --speed-limit 100 --speed-time 180 --retry 5 --retry-delay 10 -o otl_FES2004.grid https://chandler.mit.edu/ftp/GRIDS/otl_FES2004.grid"\n    exit 1\n  fi\nfi\n\ncd "$HOME/$PROJECT/tables" || exit 1\n\n# ====== PATCH: Robust sestbl. OTL settings update ======\nif [ -f sestbl. ]; then\n  cp sestbl. sestbl.before_otl_check 2>/dev/null || true\n\n  if grep -qiE \'^[[:space:]]*Use otl.grid\' sestbl.; then\n    sed -i -E \'s/^[[:space:]]*Use otl.grid.*/Use otl.grid = Y      /I\' sestbl.\n  else\n    echo "Use otl.grid = Y      " >> sestbl.\n  fi\n\n  if grep -qiE \'^[[:space:]]*Use otl.list\' sestbl.; then\n    sed -i -E \'s/^[[:space:]]*Use otl.list.*/Use otl.list = N      /I\' sestbl.\n  else\n    echo "Use otl.list = N      " >> sestbl.\n  fi\nfi\n# =====================================================\n\nrm -f otl.grid otl.list otlcmc.dat\nln -s "$OTL_GRID_MASTER" otl.grid\n\nif [ -r "$HOME/gg/tables/otl_FES2014bM_igb14_comb.list" ]; then\n  ln -s "$HOME/gg/tables/otl_FES2014bM_igb14_comb.list" otl.list\nelif [ -r "$HOME/gg/tables/otl.list" ]; then\n  ln -s "$HOME/gg/tables/otl.list" otl.list\nelse\n  echo "[WARNING] No readable otl.list found in ~/gg/tables"\nfi\n\nif [ -r "$HOME/gg/tables/otlcmc.dat" ]; then\n  ln -s "$HOME/gg/tables/otlcmc.dat" otlcmc.dat\nelse\n  echo "[WARNING] No readable otlcmc.dat found in ~/gg/tables"\nfi\n\necho "OTL link check in project tables:"\nls -lh otl.grid otl.list otlcmc.dat 2>/dev/null || true\necho "Resolved OTL targets:"\nreadlink -f otl.grid  || true\nreadlink -f otl.list  || true\nreadlink -f otlcmc.dat || true\n\ntest -r otl.grid || { echo "[ERROR] otl.grid link exists but target is not readable"; exit 1; }\nbytes=$(wc -c < otl.grid 2>/dev/null || echo 0)\nif [ "$bytes" -lt "$OTL_GRID_MIN_BYTES" ]; then\n  echo "[ERROR] otl.grid target is too small/incomplete: $bytes bytes"\n  exit 1\nfi\necho "[OK] otl.grid readable and complete-looking"\ntest -r otl.list && echo "[OK] otl.list readable" || echo "[INFO] otl.list not used because Use otl.list = N"\ntest -r otlcmc.dat && echo "[OK] otlcmc.dat readable" || echo "[WARNING] otlcmc.dat not readable"\necho "sestbl OTL settings:"\ngrep -ni "Use otl.grid\\|Use otl.list\\|Tide Model\\|ocean" sestbl. 2>/dev/null || true\n\'\'\'\n\n# =============================================================================\n# download_gzip - bounded resume-first CDDIS download\n# =============================================================================\nDOWNLOAD_FUNCTION = r\'\'\'\ndownload_gzip() {\n  outfile="$1"\n  url="$2"\n  max_attempts="${3:-8}"\n  attempt=1\n  while [ "$attempt" -le "$max_attempts" ]; do\n    if [ -s "$outfile" ] && gzip -t "$outfile" 2>/dev/null; then\n      echo "[OK] $outfile already complete"\n      return 0\n    fi\n    if [ -f "$outfile" ] && [ ! -s "$outfile" ]; then\n      rm -f "$outfile"\n    fi\n    if [ -f "$outfile" ] && ! gzip -t "$outfile" 2>/dev/null; then\n      if LC_ALL=C head -c 300 "$outfile" 2>/dev/null | grep -Eiq \'(<html|<!doctype|earthdata|login|not found|error|forbidden|unauthorized)\'; then\n        rm -f "$outfile"\n      else\n        bytes=$(wc -c < "$outfile" 2>/dev/null || echo 0)\n        echo "[INFO] Keeping partial binary gzip for resume: $outfile (${bytes} bytes)"\n      fi\n    fi\n    echo "Download attempt $attempt/$max_attempts: $outfile"\n    echo "URL: $url"\n    curl -f -L -n -C - -b "$HOME/.urs_cookies" -c "$HOME/.urs_cookies" --retry 2 --retry-delay 5 --retry-connrefused --connect-timeout 60 --max-time 240 --speed-limit 50 --speed-time 60 -o "$outfile" "$url"\n    curl_rc=$?\n    if [ -s "$outfile" ] && gzip -t "$outfile" 2>/dev/null; then\n      echo "[OK] Download complete: $outfile"\n      return 0\n    fi\n    echo "[WARNING] Download not complete yet: $outfile | curl rc=$curl_rc"\n    attempt=$((attempt + 1))\n    sleep 5\n  done\n  echo "[ERROR] Download failed after $max_attempts attempts: $outfile"\n  return 1\n}\n\'\'\'\n\ndef get_product_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + DOWNLOAD_FUNCTION + r\'\'\'\necho "Preparing SP3, IONEX and BRDC for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\nmkdir -p igs ionex brdc\ndoy="$DOY_NOW"\ndate_ymd=$(date -u -d "${YEAR}-01-01 +$((10#$doy - 1)) days" +%Y%m%d)\ngps_days=$(( ( $(date -u -d "$date_ymd" +%s) - $(date -u -d "1980-01-06" +%s) ) / 86400 ))\ngps_week=$(( gps_days / 7 ))\ngps_dow=$(( gps_days % 7 ))\nsp3_long="IGS0OPSFIN_${YEAR}${doy}0000_01D_15M_ORB.SP3.gz"\nsp3_short="igs${gps_week}${gps_dow}.sp3"\nionex_long="IGS0OPSFIN_${YEAR}${doy}0000_01D_02H_GIM.INX.gz"\nionex_short="igsg${doy}0.${YY}i"\nbrdc_gz="brdc${doy}0.${YY}n.gz"\nbrdc_short="brdc${doy}0.${YY}n"\necho "Date: $date_ymd | GPS week/day: $gps_week/$gps_dow"\necho "SP3   : $sp3_short"\necho "IONEX : $ionex_short"\necho "BRDC  : $brdc_short"\n\ncd "$HOME/$PROJECT/igs" || exit 1\nif [ -f "$sp3_short" ] && tail -1 "$sp3_short" | grep -q "EOF"; then\n  echo "[OK] Existing SP3 complete"\nelse\n  if [ "$NOFTP_FLAG" = "-noftp" ]; then\n    echo "[MISSING] SP3 in -noftp mode: $sp3_short"\n    exit 1\n  fi\n  download_gzip "$sp3_long" "https://cddis.nasa.gov/archive/gnss/products/${gps_week}/${sp3_long}" 8 || exit 1\n  gunzip -c "$sp3_long" > "$sp3_short" || exit 1\nfi\ntail -1 "$sp3_short" | grep -q "EOF" || { echo "SP3 does not end with EOF"; exit 1; }\n\ncd "$HOME/$PROJECT/ionex" || exit 1\nif [ -f "$ionex_short" ] && tail -1 "$ionex_short" | grep -q "END OF FILE"; then\n  echo "[OK] Existing IONEX complete"\nelse\n  if [ "$NOFTP_FLAG" = "-noftp" ]; then\n    echo "[MISSING] IONEX in -noftp mode: $ionex_short"\n    exit 1\n  fi\n  download_gzip "$ionex_long" "https://cddis.nasa.gov/archive/gnss/products/ionex/${YEAR}/${doy}/${ionex_long}" 10 || exit 1\n  gunzip -c "$ionex_long" > "$ionex_short" || exit 1\nfi\ntail -1 "$ionex_short" | grep -q "END OF FILE" || { echo "IONEX does not end with END OF FILE"; exit 1; }\n\ncd "$HOME/$PROJECT/brdc" || exit 1\nif [ -s "$brdc_short" ]; then\n  echo "[OK] Existing BRDC found"\nelse\n  if [ "$NOFTP_FLAG" = "-noftp" ]; then\n    echo "[MISSING] BRDC in -noftp mode: $brdc_short"\n    exit 1\n  fi\n  download_gzip "$brdc_gz" "https://cddis.nasa.gov/archive/gnss/data/daily/${YEAR}/${doy}/${YY}n/${brdc_gz}" 8 || exit 1\n  gunzip -c "$brdc_gz" > "$brdc_short" || exit 1\nfi\n[ -s "$brdc_short" ] || { echo "BRDC missing or empty"; exit 1; }\necho "Products ready for DOY $doy."\n\'\'\'\n\n# =============================================================================\n# FIXED: get_global_rinex_step - handles .Z with fallback + lowercase normalization\n# =============================================================================\ndef get_global_rinex_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + r\'\'\'\necho "Preparing/checking global IGS RINEX for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\nmkdir -p rinex control\ndoy="$DOY_NOW"\nACTIVE_IGS_FILE="$HOME/$PROJECT/control/active_igs_sites_${doy}.txt"\n\nclean_bad_global_files() {\n  cd "$HOME/$PROJECT/rinex" || exit 1\n  doy="$1"\n  echo "Cleaning invalid/empty global RINEX files for DOY $doy..."\n  for s in $IGS_SITES; do\n    for f in ${s}${doy}0.${YY}o ${s}${doy}0.${YY}d; do\n      if [ -f "$f" ] && [ ! -s "$f" ]; then rm -f "$f"; fi\n    done\n    for f in ${s}${doy}0.${YY}o.gz ${s}${doy}0.${YY}o.GZ ${s}${doy}0.${YY}o.Z \\\n             ${s}${doy}0.${YY}d.gz ${s}${doy}0.${YY}d.GZ ${s}${doy}0.${YY}d.Z; do\n      [ -f "$f" ] || continue\n      if ! gzip -t "$f" 2>/dev/null && ! file "$f" | grep -q "compress\'d data"; then\n        echo "  Removing invalid compressed file: $f"\n        rm -f "$f"\n      fi\n    done\n  done\n  cd "$HOME/$PROJECT" || exit 1\n}\n\nconvert_global_rinex_for_day() {\n  cd "$HOME/$PROJECT/rinex" || exit 1\n  doy="$1"\n\n  # Normalize first 4 characters of global short-name RINEX files to lowercase\n  echo "Normalizing first 4 characters of global short-name RINEX files to lowercase..."\n  python3 - << \'PY\'\nfrom pathlib import Path\nimport os\n\nyy = os.environ["YY"]\ndoy = os.environ.get("DOY_NOW", "")\n\nsuffixes = [\n    f".{yy}o.gz", f".{yy}o.GZ", f".{yy}o.Z", f".{yy}o",\n    f".{yy}d.gz", f".{yy}d.GZ", f".{yy}d.Z", f".{yy}d",\n]\n\nfor p in sorted(Path(".").iterdir()):\n    if not p.is_file():\n        continue\n    name = p.name\n    if doy and f"{doy}0" not in name:\n        continue\n    matched = False\n    for suf in suffixes:\n        if name.endswith(suf) and len(name) >= 7 + len(suf):\n            matched = True\n            break\n    if not matched:\n        continue\n    new_name = name[:4].lower() + name[4:]\n    if new_name == name:\n        continue\n    target = p.with_name(new_name)\n    if target.exists():\n        print(f"WARNING: Cannot rename {name} -> {new_name}; target already exists")\n        continue\n    print(f"  {name} -> {new_name}")\n    p.rename(target)\nPY\n\n  # Uncompress .o.gz/.o.GZ/.o.Z\n  echo "Uncompressing .o.gz/.o.GZ/.o.Z files if present..."\n  for f in *${doy}0.${YY}o.gz *${doy}0.${YY}o.GZ *${doy}0.${YY}o.Z; do\n    [ -f "$f" ] || continue\n    if gzip -t "$f" 2>/dev/null; then\n      echo "  gunzip -k: $f"\n      gunzip -k -f "$f" || exit 1\n    elif file "$f" | grep -q "compress\'d data"; then\n      echo "  uncompress (Z): $f"\n      gzip -cd "$f" > "${f%.Z}" 2>/dev/null || uncompress -c "$f" > "${f%.Z}" || exit 1\n    else\n      echo "  Invalid compressed, removing: $f"\n      rm -f "$f"\n    fi\n  done\n\n  # Uncompress .d.gz/.d.GZ/.d.Z (Hatanaka)\n  echo "Uncompressing Hatanaka .d.gz/.d.GZ/.d.Z files if present..."\n  for f in *${doy}0.${YY}d.gz *${doy}0.${YY}d.GZ *${doy}0.${YY}d.Z; do\n    [ -f "$f" ] || continue\n    if gzip -t "$f" 2>/dev/null; then\n      dfile="${f%.*}"\n      echo "  gunzip -c: $f -> $dfile"\n      gunzip -c "$f" > "$dfile" || exit 1\n    elif file "$f" | grep -q "compress\'d data"; then\n      dfile="${f%.Z}"\n      echo "  uncompress -c: $f -> $dfile"\n      gzip -cd "$f" > "$dfile" 2>/dev/null || uncompress -c "$f" > "$dfile" || exit 1\n    else\n      echo "  Invalid compressed, removing: $f"\n      rm -f "$f"\n    fi\n  done\n\n  # Handle long-name RINEX3 .crx.gz (including .GZ)\n  echo "Handling long-name RINEX3 .crx.gz files if present..."\n  for f in *${YEAR}${doy}0000*.crx.gz *${YEAR}${doy}0000*.CRX.gz *${YEAR}${doy}0000*.crx.GZ *${YEAR}${doy}0000*.CRX.GZ; do\n    [ -f "$f" ] || continue\n    site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n    dfile="${site}${doy}0.${YY}d"\n    ofile="${site}${doy}0.${YY}o"\n    [ -s "$ofile" ] && continue\n    gzip -t "$f" 2>/dev/null || { rm -f "$f"; continue; }\n    echo "  Long-name CRX -> short Hatanaka: $f -> $dfile"\n    gunzip -c "$f" > "$dfile" || { rm -f "$dfile"; continue; }\n    command -v crx2rnx >/dev/null 2>&1 || { echo "crx2rnx not found"; exit 1; }\n    crx2rnx "$dfile"\n    [ -s "$ofile" ] || rm -f "$ofile"\n  done\n\n  # Handle long-name RINEX3 .rnx.gz (including .GZ)\n  echo "Handling long-name RINEX3 .rnx.gz files if present..."\n  for f in *${YEAR}${doy}0000*.rnx.gz *${YEAR}${doy}0000*.RNX.gz *${YEAR}${doy}0000*.rnx.GZ *${YEAR}${doy}0000*.RNX.GZ; do\n    [ -f "$f" ] || continue\n    site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n    ofile="${site}${doy}0.${YY}o"\n    [ -s "$ofile" ] && continue\n    gzip -t "$f" 2>/dev/null || { rm -f "$f"; continue; }\n    echo "  Long-name RNX -> short observation: $f -> $ofile"\n    gunzip -c "$f" > "$ofile" || rm -f "$ofile"\n  done\n\n  # Convert any remaining .d files (short-name Hatanaka)\n  echo "Converting Hatanaka .d to .o if present..."\n  for f in *${doy}0.${YY}d; do\n    [ -f "$f" ] || continue\n    command -v crx2rnx >/dev/null 2>&1 || { echo "crx2rnx not found"; exit 1; }\n    ofile="${f%.${YY}d}.${YY}o"\n    [ -s "$ofile" ] && continue\n    echo "  crx2rnx: $f"\n    crx2rnx "$f"\n    [ -s "$ofile" ] || rm -f "$ofile"\n  done\n\n  cd "$HOME/$PROJECT" || exit 1\n}\n\ncheck_available_igs() {\n  cd "$HOME/$PROJECT" || exit 1\n  doy="$1"\n  active=""\n  missing=""\n  for s in $IGS_SITES; do\n    f="rinex/${s}${doy}0.${YY}o"\n    if [ -s "$f" ]; then\n      echo "[OK] Global RINEX ready: $s"\n      active="$active $s"\n    else\n      echo "[MISSING] Global RINEX not ready: $s"\n      missing="$missing $s"\n    fi\n  done\n  active=$(echo "$active" | xargs)\n  missing=$(echo "$missing" | xargs)\n  echo "$active" > "$ACTIVE_IGS_FILE"\n  echo "Active IGS stations for DOY $doy: ${active:-NONE}"\n  echo "Missing IGS stations for DOY $doy: ${missing:-NONE}"\n  n_active=$(echo "$active" | wc -w)\n  if [ "$n_active" -lt 3 ]; then\n    echo "ERROR: Less than 3 IGS stations are available."\n    exit 1\n  fi\n  cd "$HOME/$PROJECT/tables" || exit 1\n  cp sites.defaults "sites.defaults.before_active_igs_${doy}" 2>/dev/null || true\n  {\n    echo "# Active IGS/reference stations for DOY $doy"\n    for s in $active; do echo " ${s}_gps $EXPT ftprnx"; done\n    echo ""\n    echo "# Local CORS stations"\n    for s in $LOCAL_SITES; do echo " ${s}_gps $EXPT localrx"; done\n  } > sites.defaults\n  cat sites.defaults\n}\n\nclean_bad_global_files "$doy"\nconvert_global_rinex_for_day "$doy"\n\nmissing_before=0\nfor s in $IGS_SITES; do\n  [ -s "rinex/${s}${doy}0.${YY}o" ] || missing_before=1\ndone\n\nif [ "$missing_before" -eq 0 ]; then\n  check_available_igs "$doy"\n  exit 0\nfi\n\nif [ "$NOFTP_FLAG" = "-noftp" ] || [ "$DOWNLOAD_GLOBAL_RINEX" != "YES" ]; then\n  check_available_igs "$doy"\n  exit 0\nfi\n\nif ! command -v sh_get_rinex >/dev/null 2>&1; then\n  echo "sh_get_rinex not found. Cannot download global RINEX."\n  check_available_igs "$doy"\n  exit 0\nfi\n\ncd "$HOME/$PROJECT/rinex" || exit 1\nif command -v timeout >/dev/null 2>&1; then\n  timeout 900 sh_get_rinex -archive cddis -yr "$YEAR" -doy "$doy" -ndays 1 -sites $IGS_SITES -ftp_prog curl -inv -xcheck N\nelse\n  sh_get_rinex -archive cddis -yr "$YEAR" -doy "$doy" -ndays 1 -sites $IGS_SITES -ftp_prog curl -inv -xcheck N\nfi\ncd "$HOME/$PROJECT" || exit 1\nclean_bad_global_files "$doy"\nconvert_global_rinex_for_day "$doy"\ncheck_available_igs "$doy"\n\'\'\'\n\n# =============================================================================\n# FIXED: get_gamit_step - SOLVE Normal stop + h-file success logic\n# =============================================================================\ndef get_gamit_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + r\'\'\'\necho "Running GAMIT for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\ndoy="$DOY_NOW"\nACTIVE_IGS_FILE="$HOME/$PROJECT/control/active_igs_sites_${doy}.txt"\n\nif [ -s "$ACTIVE_IGS_FILE" ]; then\n  ACTIVE_IGS_SITES=$(cat "$ACTIVE_IGS_FILE")\nelse\n  ACTIVE_IGS_SITES="$IGS_SITES"\nfi\n\n# -----------------------------------------------------------------------------\n# IMPORTANT PATCH: clean per-day RINEX sandbox\n# -----------------------------------------------------------------------------\n# Earlier version allowed sh_gamit cleanup/linking from one day to leave the\n# common rinex/ folder in a mixed state. Then the next day could fail with:\n#   MAKEXP: No RINEX or X-files found\n# This patch keeps rinex_all/ as a master pool and rebuilds rinex/ with ONLY the\n# current DOY files before every sh_gamit run. This prevents previous-day files,\n# compressed cleanup products, truncated downloads, or long-name leftovers from\n# confusing sh_link_rinex.\nprepare_clean_rinex_for_day() {\n  day="$1"\n  mkdir -p rinex rinex_all control\n  echo "Preparing clean per-day RINEX folder for DOY $day..."\n\n  shopt -s nullglob\n  # Save every existing observation/Hatanaka file to the master pool first.\n  for f in rinex/*.${YY}o rinex/*.${YY}d \\\n           rinex/*.${YY}o.gz rinex/*.${YY}o.GZ rinex/*.${YY}o.Z \\\n           rinex/*.${YY}d.gz rinex/*.${YY}d.GZ rinex/*.${YY}d.Z \\\n           rinex/*${YEAR}*.crx.gz rinex/*${YEAR}*.CRX.gz \\\n           rinex/*${YEAR}*.rnx.gz rinex/*${YEAR}*.RNX.gz; do\n    [ -f "$f" ] || continue\n    cp -pf "$f" rinex_all/ 2>/dev/null || true\n  done\n\n  # Remove all observation files from working rinex/ so sh_link_rinex sees\n  # only the current day. Product/nav files are not stored here and are untouched.\n  rm -f rinex/*.${YY}o rinex/*.${YY}d \\\n        rinex/*.${YY}o.gz rinex/*.${YY}o.GZ rinex/*.${YY}o.Z \\\n        rinex/*.${YY}d.gz rinex/*.${YY}d.GZ rinex/*.${YY}d.Z \\\n        rinex/*${YEAR}*.crx.gz rinex/*${YEAR}*.CRX.gz \\\n        rinex/*${YEAR}*.rnx.gz rinex/*${YEAR}*.RNX.gz 2>/dev/null || true\n\n  restore_one_site() {\n    site="$1"\n    day="$2"\n    site_u=$(echo "$site" | tr \'[:lower:]\' \'[:upper:]\')\n    base="${site}${day}0.${YY}"\n    out="rinex/${base}o"\n\n    [ -s "$out" ] && return 0\n\n    if [ -s "rinex_all/${base}o" ]; then\n      cp -pf "rinex_all/${base}o" "$out"\n      return 0\n    fi\n    if [ -s "rinex_all/${base}o.gz" ]; then\n      gunzip -c "rinex_all/${base}o.gz" > "$out" && [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}o.GZ" ]; then\n      gunzip -c "rinex_all/${base}o.GZ" > "$out" && [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}o.Z" ]; then\n      gzip -cd "rinex_all/${base}o.Z" > "$out" 2>/dev/null || uncompress -c "rinex_all/${base}o.Z" > "$out"\n      [ -s "$out" ] && return 0\n    fi\n\n    if [ -s "rinex_all/${base}d" ]; then\n      cp -pf "rinex_all/${base}d" "rinex/${base}d"\n      ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}d.gz" ]; then\n      gunzip -c "rinex_all/${base}d.gz" > "rinex/${base}d" && ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}d.GZ" ]; then\n      gunzip -c "rinex_all/${base}d.GZ" > "rinex/${base}d" && ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}d.Z" ]; then\n      gzip -cd "rinex_all/${base}d.Z" > "rinex/${base}d" 2>/dev/null || uncompress -c "rinex_all/${base}d.Z" > "rinex/${base}d"\n      ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n\n    long_crx=$(ls rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.crx.gz rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.CRX.gz 2>/dev/null | head -1 || true)\n    if [ -n "$long_crx" ] && [ -s "$long_crx" ]; then\n      gunzip -c "$long_crx" > "rinex/${base}d" && ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    long_rnx=$(ls rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.rnx.gz rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.RNX.gz 2>/dev/null | head -1 || true)\n    if [ -n "$long_rnx" ] && [ -s "$long_rnx" ]; then\n      gunzip -c "$long_rnx" > "$out" && [ -s "$out" ] && return 0\n    fi\n\n    return 1\n  }\n\n  missing_restore=0\n  for s in $LOCAL_SITES $ACTIVE_IGS_SITES; do\n    if restore_one_site "$s" "$day"; then\n      echo "[OK] restored for GAMIT: $s"\n    else\n      echo "[MISSING] could not restore current-day RINEX: $s"\n      missing_restore=1\n    fi\n  done\n\n  echo "Working rinex/ files for DOY $day:"\n  ls -1 rinex/*${day}0.${YY}o 2>/dev/null | sed \'s#^#  #\' || true\n\n  n_work=$(ls rinex/*${day}0.${YY}o 2>/dev/null | wc -l)\n  if [ "$n_work" -lt 3 ]; then\n    echo "ERROR: Too few current-day RINEX files in working rinex/: $n_work"\n    return 1\n  fi\n  [ "$missing_restore" -eq 0 ] || return 1\n  return 0\n}\n\nrefresh_sites_defaults_for_day() {\n  day="$1"\n  cd "$HOME/$PROJECT/tables" || exit 1\n  cp sites.defaults "sites.defaults.before_gamit_${day}" 2>/dev/null || true\n  {\n    echo "# Active IGS/reference stations for DOY $day"\n    for s in $ACTIVE_IGS_SITES; do echo " ${s}_gps $EXPT ftprnx"; done\n    echo ""\n    echo "# Local CORS stations"\n    for s in $LOCAL_SITES; do echo " ${s}_gps $EXPT localrx"; done\n  } > sites.defaults\n  cd "$HOME/$PROJECT" || exit 1\n}\n\nprepare_clean_rinex_for_day "$doy" || { echo "ERROR: Could not prepare clean RINEX for DOY $doy"; exit 1; }\nrefresh_sites_defaults_for_day "$doy"\n\necho "Local stations      : $LOCAL_SITES"\necho "Active IGS stations : $ACTIVE_IGS_SITES"\n\nmissing=0\nfor s in $LOCAL_SITES; do\n  f="rinex/${s}${doy}0.${YY}o"\n  [ -s "$f" ] && echo "[OK] Local RINEX: $s" || { echo "[MISSING] Local RINEX: $s"; missing=1; }\ndone\nfor s in $ACTIVE_IGS_SITES; do\n  f="rinex/${s}${doy}0.${YY}o"\n  [ -s "$f" ] && echo "[OK] IGS RINEX: $s" || { echo "[MISSING] IGS RINEX: $s"; missing=1; }\ndone\n\nn_igs=$(echo "$ACTIVE_IGS_SITES" | wc -w)\n[ "$n_igs" -ge 3 ] || { echo "ERROR: Less than 3 active IGS stations"; exit 1; }\n[ "$missing" -eq 0 ] || { echo "Required RINEX files are missing"; exit 1; }\n\ndate_ymd=$(date -u -d "${YEAR}-01-01 +$((10#$doy - 1)) days" +%Y%m%d)\ngps_days=$(( ( $(date -u -d "$date_ymd" +%s) - $(date -u -d "1980-01-06" +%s) ) / 86400 ))\ngps_week=$(( gps_days / 7 ))\ngps_dow=$(( gps_days % 7 ))\nsp3_short="igs${gps_week}${gps_dow}.sp3"\n\n[ -s "igs/$sp3_short" ] || { echo "Missing SP3: igs/$sp3_short"; exit 1; }\n[ -s "brdc/brdc${doy}0.${YY}n" ] || { echo "Missing BRDC: brdc/brdc${doy}0.${YY}n"; exit 1; }\n[ -s "ionex/igsg${doy}0.${YY}i" ] || { echo "Missing IONEX: ionex/igsg${doy}0.${YY}i"; exit 1; }\n\nrm -rf "${doy}G"\n\necho "Command:"\necho "sh_gamit -d $YY $doy -gnss G -expt $EXPT -orbit igsf -aprfile $CUSTOM_APR_FILE -noftp"\n\nsh_gamit -d "$YY" "$doy" -gnss G -expt "$EXPT" -orbit igsf -aprfile "$CUSTOM_APR_FILE" -noftp 2>&1 | tee "sh_gamit_${doy}.log"\nrc=${PIPESTATUS[0]}\necho "sh_gamit return code: $rc"\n\nsolve_ok=0\nhfile_ok=0\n\nif grep -qi "SOLVE/solve: Normal stop" "sh_gamit_${doy}.log"; then\n  solve_ok=1\n  echo "[OK] DOY $doy completed with SOLVE Normal stop."\nelse\n  echo "[ERROR] SOLVE Normal stop not found."\n  grep -Ei "FATAL|ERROR|Normal stop|STOP|No RINEX|No X-files|No RINEX or X-files" "sh_gamit_${doy}.log" | tail -120 || true\nfi\n\nif ls "${doy}G"/h*.${YY}${doy} >/dev/null 2>&1; then\n  hfile_ok=1\n  echo "[OK] Real GAMIT h-file created:"\n  ls -lh "${doy}G"/h*.${YY}${doy}\nelse\n  echo "[ERROR] No real h-file h*.${YY}${doy} was detected."\n  ls -lh "${doy}G"/h* 2>/dev/null || true\nfi\n\nif [ "$solve_ok" -eq 1 ] && [ "$hfile_ok" -eq 1 ]; then\n  if [ "$rc" -ne 0 ]; then\n    echo "[WARNING] sh_gamit returned code $rc, but SOLVE Normal stop and h-file are present."\n    echo "[WARNING] Treating this day as successful but please review the log."\n  fi\nelse\n  echo "[ERROR] GAMIT day $doy failed because SOLVE Normal stop or h-file is missing."\n  echo "[INFO] Current working rinex files were:"\n  ls -lh rinex/*${doy}0.${YY}o 2>/dev/null || true\n  exit 1\nfi\n\nreal_fatal_lines=$(grep -Ei "FATAL" "sh_gamit_${doy}.log" | grep -Evi "Removing existing GAMIT\\.\\[status\\]\\[warning\\]\\[fatal\\] files" | grep -Evi "GAMIT\\.\\[status\\]\\[warning\\]\\[fatal\\]" || true)\nif [ -n "$real_fatal_lines" ]; then\n  echo "[WARNING] Word FATAL found in log, but SOLVE Normal stop and h-file were reached."\n  echo "$real_fatal_lines" | tail -30\nfi\n\'\'\'\n\n# =============================================================================\n# get_qc_step - Shows local stations individually\n# =============================================================================\ndef get_qc_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + r\'\'\'\necho "Quality check for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\ndoy="$DOY_NOW"\n\necho "----- SOLVE/FATAL/ERROR status -----"\ngrep -i "SOLVE/solve: Normal stop\\|FATAL\\|ERROR" "sh_gamit_${doy}.log" 2>/dev/null | grep -vi "GAMIT.\\[status\\]\\[warning\\]\\[fatal\\]" | tail -100 || true\n\necho ""\necho "----- NRMS -----"\ngrep -i "nrms" "${doy}G/sh_gamit_${doy}G.summary" 2>/dev/null || echo "No NRMS found"\n\necho ""\necho "----- H-files -----"\nls -lh "${doy}G"/h*.${YY}${doy} 2>/dev/null || echo "No real h-file h*.${YY}${doy} found"\n\necho ""\necho "----- Local station AUTCLN summary -----"\nif [ -s "${doy}G/autcln.post.sum" ]; then\n  found=0\n  for s in $LOCAL_SITES; do\n    U=$(echo "$s" | tr \'[:lower:]\' \'[:upper:]\')\n    if grep -q "$U" "${doy}G/autcln.post.sum"; then\n      found=1\n      echo ""\n      echo "### $U ###"\n      grep "$U" "${doy}G/autcln.post.sum" | head -20\n    fi\n  done\n  if [ "$found" -eq 0 ]; then\n    echo "No local station names directly found in autcln.post.sum."\n    head -40 "${doy}G/autcln.post.sum"\n  fi\nelse\n  echo "autcln.post.sum not found"\nfi\n\necho ""\necho "----- BAD Pre-RNG -----"\nzgrep -i "BAD Pre-RNG" "${doy}G/autcln.out.gz" 2>/dev/null | head -50 || echo "No BAD Pre-RNG lines found"\n\necho "QC complete for DOY $doy."\n\'\'\'\n\n# =============================================================================\n# SCRIPT RUNNER\n# =============================================================================\ndef export_block(settings: Dict[str, str]) -> str:\n    lines = ["set -o pipefail", "set +e"]\n    for k in [\n        "PROJECT", "EXPT", "YEAR", "YY", "START_DOY", "NDAYS",\n        "SOURCE_RINEX_DIR", "LOCAL_SITES", "IGS_SITES", "EXCLUDE_SITES",\n        "RENAME_SITE", "RENAME_PAIRS", "CONFLICT_SITE", "REF_FRAME",\n        "APR_FILE", "CUSTOM_APR_FILE", "NOFTP_FLAG", "FRESH_START",\n        "DOWNLOAD_GLOBAL_RINEX", "STRICT_NOFTP_CHECK",\n    ]:\n        lines.append(f"export {k}={q(settings.get(k, \'\'))}")\n    lines.append("export END_DOY=$((10#$START_DOY + NDAYS - 1))")\n    return "\\n".join(lines) + "\\n"\n\ndef run_bash_script(step_name: str, bash_code: str, settings: Dict[str, str], log_dir: Path) -> bool:\n    safe = "".join(c if c.isalnum() else "_" for c in step_name.lower())[:60]\n    script_path = log_dir / f"{safe}.sh"\n    log_path = log_dir / f"{safe}.log"\n    script_path.write_text(export_block(settings) + "\\n" + bash_code, encoding="utf-8")\n    os.chmod(script_path, 0o755)\n    print_progress(f"Running step: {step_name}")\n    print_info(f"Script: {script_path}")\n    print_info(f"Log   : {log_path}")\n    proc = None\n    rc = 1\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as log:\n            proc = subprocess.Popen(\n                ["/bin/bash", str(script_path)],\n                stdout=subprocess.PIPE,\n                stderr=subprocess.STDOUT,\n                text=True,\n                bufsize=1,\n                preexec_fn=os.setsid,\n            )\n            assert proc.stdout is not None\n            for line in proc.stdout:\n                print(line, end="")\n                log.write(line)\n            rc = proc.wait()\n    except KeyboardInterrupt:\n        print_warning("User pressed Ctrl+C")\n        if proc is not None:\n            try:\n                os.killpg(os.getpgid(proc.pid), signal.SIGTERM)\n            except Exception:\n                pass\n        return False\n    if rc == 0:\n        print_success(f"Step finished: {step_name}")\n        return True\n    print_error(f"Step failed: {step_name} | Return code: {rc}")\n    print_info(f"Check log: {log_path}")\n    return False\n\ndef run_critical(step_name: str, bash_code: str, settings: Dict[str, str], log_dir: Path, allow_continue: bool = False) -> None:\n    while True:\n        ok = run_bash_script(step_name, bash_code, settings, log_dir)\n        if ok:\n            return\n        ans = ask_retry_continue_quit()\n        if ans == "r":\n            continue\n        if ans == "c":\n            if allow_continue:\n                return\n            print_warning("Continuing a critical failed step can break later steps.")\n            if ask_yes_no("Continue anyway?", "no"):\n                return\n            continue\n        sys.exit(1)\n\n# =============================================================================\n# DATA-FIRST DECISION HELPERS\n# =============================================================================\ndef expected_doy_list(start_doy: str, ndays: str) -> List[str]:\n    start = int(norm_doy(start_doy))\n    n = int(ndays)\n    return [f"{d:03d}" for d in range(start, start + n)]\n\ndef file_doy(file_path: str, yy: str) -> str | None:\n    core = strip_rinex_suffix(Path(file_path).name, yy)\n    if core is None or len(core) < 7:\n        return None\n    return core[4:7]\n\ndef prefer_file(files: List[str]) -> str:\n    def rank(name: str) -> int:\n        if re.search(r"\\.\\d\\do$", name):\n            return 0\n        if re.search(r"\\.\\d\\do\\.(gz|GZ)$", name):\n            return 1\n        if re.search(r"\\.\\d\\dd$", name):\n            return 2\n        if re.search(r"\\.\\d\\dd\\.(gz|GZ)$", name):\n            return 3\n        return 9\n    return sorted(files, key=lambda f: (rank(Path(f).name), Path(f).name))[0]\n\ndef station_quality(info: dict, expected_doys: List[str], yy: str) -> Dict[str, object]:\n    by_doy: Dict[str, List[str]] = {}\n    for f in info.get("files", []):\n        d = file_doy(f, yy)\n        if d:\n            by_doy.setdefault(d, []).append(f)\n    available = []\n    missing = []\n    partial = []\n    need_conversion = []\n    epochs = []\n    for d in expected_doys:\n        files = by_doy.get(d, [])\n        if not files:\n            missing.append(d)\n            continue\n        available.append(d)\n        f = prefer_file(files)\n        name = Path(f).name\n        if re.search(r"\\.\\d\\dd(\\.gz|\\.GZ|\\.Z)?$", name) or name.endswith(".Z"):\n            need_conversion.append(d)\n            continue\n        md = read_rinex_metadata(f)\n        ep = int(md.get("num_epochs", 0) or 0)\n        epochs.append(ep)\n        if ep < 2500:\n            partial.append(d)\n    if len(available) == 0:\n        status = "NO_DATA"\n    elif missing:\n        status = "MISSING_DAYS"\n    elif partial:\n        status = "PARTIAL"\n    elif need_conversion:\n        status = "NEEDS_CONV"\n    else:\n        status = "OK"\n    return {\n        "available": available,\n        "missing": missing,\n        "partial": partial,\n        "need_conversion": need_conversion,\n        "min_epochs": min(epochs) if epochs else None,\n        "max_epochs": max(epochs) if epochs else None,\n        "status": status,\n    }\n\ndef show_data_decision_table(station_info: Dict[str, dict], expected_doys: List[str], yy: str) -> None:\n    print_header("DATA STATUS TABLE - DECIDE AFTER SEEING THIS")\n    print_info("Station code shown here is only the source RINEX file code.")\n    print_info("After this table, you will decide: keep, exclude, or rename.")\n    print_info("Expected DOYs: " + " ".join(expected_doys))\n    print()\n    print(f"{\'Source\':<8} {\'Files\':>5} {\'Days\':>9} {\'Missing\':<18} {\'Partial\':<18} {\'Epochs min-max\':<15} {\'Status\':<12}")\n    print(ctext("-" * 95, Colors.CYAN))\n    for st in sorted(station_info):\n        qinfo = station_quality(station_info[st], expected_doys, yy)\n        files = len(station_info[st].get("files", []))\n        days = f"{len(qinfo[\'available\'])}/{len(expected_doys)}"\n        missing = " ".join(qinfo["missing"]) if qinfo["missing"] else "-"\n        partial = " ".join(qinfo["partial"]) if qinfo["partial"] else "-"\n        ep = "-" if qinfo["min_epochs"] is None else f"{qinfo[\'min_epochs\']}-{qinfo[\'max_epochs\']}"\n        status = str(qinfo["status"])\n        color = Colors.GREEN if status == "OK" else (Colors.YELLOW if status in ("NEEDS_CONV", "PARTIAL") else Colors.RED)\n        print(f"{st:<8} {files:>5} {days:>9} {missing:<18} {partial:<18} {ep:<15} {ctext(f\'{status:<12}\', color)}")\n    print(ctext("-" * 95, Colors.CYAN))\n    print_info("You may still process a PARTIAL station if you want. The program does not decide for you.")\n\ndef station_detail_loop(station_info: Dict[str, dict]) -> None:\n    while ask_yes_no("View detailed header/epoch information for any station?", "no"):\n        st = ask_input("Enter station code to view details", "").lower().strip()\n        if st:\n            show_station_details(st, station_info)\n\ndef get_partial_stations(station_info: Dict[str, dict], expected_doys: List[str], yy: str) -> Tuple[List[str], List[str]]:\n    partial = []\n    ok = []\n    for st in station_info:\n        qinfo = station_quality(station_info[st], expected_doys, yy)\n        status = qinfo.get("status", "NO_DATA")\n        if status in ("OK", "NEEDS_CONV"):\n            ok.append(st)\n        else:\n            partial.append(st)\n    return sorted(partial), sorted(ok)\n\ndef ask_source_station_selection(stations: List[str], station_info: Dict[str, dict], expected_doys: List[str], yy: str) -> Tuple[str, str]:\n    print_header("SELECT SOURCE STATIONS FOR PROCESSING")\n    partial_stations, ok_stations = get_partial_stations(station_info, expected_doys, yy)\n    detected_sites = sorted(stations)\n    default_keep = ok_stations.copy() if ok_stations else detected_sites.copy()\n    default_text = " ".join(default_keep)\n    if partial_stations:\n        print_warning("The following stations have partial/missing data:")\n        for st in partial_stations:\n            qinfo = station_quality(station_info[st], expected_doys, yy)\n            print(f"  {st}: missing={qinfo.get(\'missing\', [])}, partial={qinfo.get(\'partial\', [])}")\n        if ask_yes_no(f"Exclude all partial stations ({len(partial_stations)} station(s)) from processing?", "yes"):\n            default_keep = [s for s in default_keep if s not in partial_stations]\n            default_text = " ".join(default_keep)\n    print_success("Detected local RINEX stations: " + " ".join(detected_sites))\n    print_info("Default keep list: " + (default_text if default_text else "None"))\n    print_info("Type all to keep all detected stations.")\n    while True:\n        selected = norm_sites(ask_input("Source station codes to keep", default_text))\n        if selected.strip().lower() == "all":\n            selected_list = detected_sites\n            selected = " ".join(detected_sites)\n        else:\n            if selected == "":\n                selected = default_text\n            selected_list = station_list(selected)\n        unknown = sorted(set(selected_list) - set(detected_sites))\n        if unknown:\n            print_error("Station codes not found in scan: " + " ".join(unknown))\n            continue\n        if not selected_list:\n            print_error("At least one source station must be selected.")\n            continue\n        selected_partial = [s for s in selected_list if s in partial_stations]\n        if selected_partial and not ask_yes_no("Continue with selected PARTIAL stations?", "no"):\n            continue\n        exclude_sites = " ".join(sorted(set(detected_sites) - set(selected_list)))\n        print_success("Source stations selected: " + selected)\n        print_warning("Stations to exclude: " + (exclude_sites if exclude_sites else "None"))\n        if ask_yes_no("Confirm this station selection?", "yes"):\n            return selected, exclude_sites\n\ndef ask_rename_pairs_data_first(source_sites: str, apr_file: str) -> Tuple[str, str, str, str]:\n    print_header("OPTIONAL RENAME - USER DECIDES")\n    source_list = station_list(source_sites)\n    apr_matches = [s for s in source_list if apr_has_station(apr_file, s)]\n    if apr_matches:\n        print_warning("Selected source codes also appear in APR file: " + " ".join(apr_matches))\n    rename_pairs_str = ""\n    if ask_yes_no("Do you want to rename any selected source station?", "no"):\n        while True:\n            rename_pairs_str = norm_sites(ask_input("Enter rename pairs, example old:new", ""))\n            pairs = parse_rename_pairs(rename_pairs_str)\n            if not pairs:\n                rename_pairs_str = ""\n                break\n            old_names = [old for old, _ in pairs]\n            unknown_old = sorted(set(old_names) - set(source_list))\n            bad = [f"{old}:{new}" for old, new in pairs if not validate_station_code(old) or not validate_station_code(new)]\n            if unknown_old:\n                print_error("Rename OLD code not selected: " + " ".join(unknown_old))\n                continue\n            if bad:\n                print_error("Invalid rename pairs: " + " ".join(bad))\n                continue\n            break\n    pairs = parse_rename_pairs(rename_pairs_str)\n    rename_map = {old: new for old, new in pairs}\n    final_sites = " ".join([rename_map.get(s, s) for s in source_list])\n    rename_site = "YES" if pairs else "NO"\n    default_conflicts = [old.upper() for old, _new in pairs if apr_has_station(apr_file, old)]\n    conflict_site = ""\n    if default_conflicts:\n        text = " ".join(sorted(set(default_conflicts)))\n        if ask_yes_no("Remove old renamed station entries from custom APR? " + text, "yes"):\n            conflict_site = normalize_conflict_sites(text)\n    if ask_yes_no("Do you want to manually enter any APR conflict site to remove?", "no"):\n        manual = ask_input("APR conflict site(s), example HYDE ABCD or HYDE_GPS", conflict_site.replace("_GPS", ""))\n        conflict_site = normalize_conflict_sites(manual)\n    print_success("Final GAMIT local station codes: " + final_sites)\n    print_success("Rename setting: " + rename_site + (f" ({rename_pairs_str})" if rename_pairs_str else ""))\n    print_success("APR conflict removal: " + (conflict_site if conflict_site else "None"))\n    return final_sites, rename_site, rename_pairs_str, conflict_site\n\n\ndef choose_reference_frame_and_apr() -> Tuple[str, str, str]:\n    print_header("REFERENCE FRAME AND APR FILE")\n    frame_options = ["IGS20 / ITRF2020", "IGS14 / ITRF2014", "ITRF08 / IGS08"]\n    frame_index = ask_choice_index("Choose APR/frame family", frame_options, 0)\n    ref_frame = ["IGS20", "IGS14", "ITRF08"][frame_index]\n\n    apr_file = auto_select_apr_file(ref_frame)\n    while True:\n        if not apr_file or not (Path.home() / "gg" / "tables" / apr_file).is_file():\n            show_available_apr_files()\n            default = {\n                "IGS20": "igb20_comb.apr",\n                "IGS14": "igs14_comb.apr",\n                "ITRF08": "All_PBO_igs08.apr",\n            }.get(ref_frame, apr_file)\n            apr_file = ask_input("Enter APR file name exactly from ~/gg/tables", default)\n        else:\n            print_success(f"Auto-selected APR file: {apr_file}")\n            if not ask_yes_no("Use this APR file?", "yes"):\n                show_available_apr_files()\n                apr_file = ask_input("Enter APR file name exactly from ~/gg/tables", apr_file)\n\n        if not (Path.home() / "gg" / "tables" / apr_file).is_file():\n            print_error(f"APR file not found in ~/gg/tables/: {apr_file}")\n            apr_file = ""\n            continue\n\n        if apr_matches_frame_name(ref_frame, apr_file):\n            break\n\n        print_error("APR file does not match selected reference frame.")\n        print_error(f"Selected frame: {ref_frame}")\n        print_error(f"Selected APR  : {apr_file}")\n        print_info("Examples:")\n        print("  IGS20 -> igb20_comb.apr / igs20.apr / itrf20*.apr")\n        print("  IGS14 -> igs14_comb.apr / igb14_comb.apr / itrf14*.apr")\n        print("  ITRF08 -> All_PBO_igs08.apr / igs08_comb.apr / igb08_comb.apr / itrf08*.apr")\n        apr_file = ""\n\n    custom_apr_file = f"custom_{ref_frame.lower()}.apr"\n    print_success(f"Reference frame locked: {ref_frame}")\n    print_success(f"APR file locked       : {apr_file}")\n    print_success(f"Custom APR will be    : {custom_apr_file}")\n    return ref_frame, apr_file, custom_apr_file\n\n# =============================================================================\n# FIXED: postprocess_summary - robust station parser, uppercase content\n# =============================================================================\ndef postprocess_summary(settings: Dict[str, str], doy_list: List[str], log_dir: Path) -> None:\n    project_dir = Path.home() / settings["PROJECT"]\n    yy = settings["YY"]\n\n    print_header("APR / ITRF CONFIRMATION FOR ALL DAYS")\n    for doy in doy_list:\n        log = project_dir / f"sh_gamit_{doy}.log"\n        print()\n        print(f"DOY {doy}")\n        if not log.exists():\n            print_warning(f"  Missing log: {log}")\n            continue\n        text = log.read_text(errors="ignore")\n        m = re.search(r"Input options -d .*?-aprfile\\s+(\\S+)", text)\n        if m:\n            print_success(f"  APR file used by sh_gamit: {m.group(1)}")\n        else:\n            print_info(f"  APR file expected from settings: {settings[\'CUSTOM_APR_FILE\']}")\n        print_success(f"  Selected frame family: {settings[\'REF_FRAME\']}")\n        for line in text.splitlines():\n            if "Updating lfile. with coordinates from:" in line:\n                print_info("  " + line.strip())\n                break\n\n    print_header("H-FILE AND SOLUTION CHECK - ALL DAYS")\n    good_days = 0\n\n    for doy in doy_list:\n        day_dir = project_dir / f"{doy}G"\n        hfiles = sorted([p for p in day_dir.glob(f"h*.{yy}{doy}") if p.is_file() and p.stat().st_size > 0])\n        summary_file = day_dir / f"sh_gamit_{doy}G.summary"\n        log_file = project_dir / f"sh_gamit_{doy}.log"\n\n        print()\n        print(ctext(f"DOY {doy}", Colors.CYAN + Colors.BOLD))\n\n        log_ok = False\n        if log_file.exists():\n            log_text = log_file.read_text(errors="ignore")\n            log_ok = "SOLVE/solve: Normal stop" in log_text\n            print_success("  SOLVE Normal stop found") if log_ok else print_warning("  SOLVE Normal stop not found")\n        else:\n            print_warning("  sh_gamit log not found")\n\n        station_ok = False\n        if hfiles:\n            hfile = hfiles[0]\n            print_success(f"  H-file: {hfile.name} ({hfile.stat().st_size} bytes)")\n            content = hfile.read_text(errors="ignore").upper()\n            station_markers = sorted(set(re.findall(r"\\b([A-Z0-9]{4}_[A-Z0-9]{3})\\b", content)))\n            station_codes = sorted(set(m.split("_")[0] for m in station_markers))\n            m_count = re.search(r"Number of stations:\\s*([0-9]+)", content, re.IGNORECASE)\n            if m_count:\n                header_count = int(m_count.group(1))\n                print_success(f"  Number of stations from h-file header: {header_count}")\n            print_success(f"  Unique station codes parsed from h-file: {len(station_codes)}")\n            if station_codes:\n                print_info(\n                    "  Stations: "\n                    + " ".join(station_codes[:25])\n                    + (f" ... +{len(station_codes)-25} more" if len(station_codes) > 25 else "")\n                )\n            local_upper = [s.upper() for s in station_list(settings["LOCAL_SITES"])]\n            found = [s for s in local_upper if s in station_codes]\n            missing = [s for s in local_upper if s not in station_codes]\n            if found:\n                print_success("  Local stations found: " + ", ".join(found))\n            if missing:\n                print_warning("  Local stations missing: " + ", ".join(missing))\n            station_ok = len(missing) == 0\n        else:\n            print_warning("  H-file not found")\n\n        nrms_vals = []\n        if summary_file.exists():\n            with open(summary_file, "r", errors="ignore") as f:\n                for line in f:\n                    if "Postfit nrms:" in line:\n                        try:\n                            nrms_vals.append(float(line.split("Postfit nrms:")[1].strip().split()[0]))\n                        except Exception:\n                            pass\n            if nrms_vals:\n                print_success("  Postfit NRMS values: " + ", ".join(f"{v:.4f}" for v in nrms_vals))\n                print_success("  NRMS quality looks good") if max(nrms_vals) < 0.5 else print_warning("  NRMS needs review")\n            else:\n                print_info("  No Postfit NRMS values parsed")\n        else:\n            print_warning("  Summary file not found")\n\n        if log_ok and hfiles and nrms_vals and max(nrms_vals) < 0.5 and station_ok:\n            good_days += 1\n\n    print_header("FINAL GAMIT STATUS")\n    print_success(f"Good-looking days: {good_days}/{len(doy_list)}")\n    if good_days == len(doy_list):\n        print_success("GAMIT run is successful for all processed days.")\n    else:\n        print_warning("Some days need review. Check logs and h-files above.")\n\n    print_header("NEXT STEPS FOR GLOBK")\n    print_info("GLOBK/GLORG is not run in this program.")\n    print(f"  cd ~/{settings[\'PROJECT\']}")\n    print(f"  find . -path \'./???G/h*.{settings[\'YY\']}???\' -type f | sort > hfile_list.txt")\n    print("  # Then run separate autom_globk.py or prepare proper GLOBK command/control files")\n    print_warning("For final scientific results, correct antenna heights and receiver/antenna metadata in station.info.")\n    print_info(f"Processing logs are saved in: {log_dir}")\n\n# =============================================================================\n# MAIN PROGRAM\n# =============================================================================\ndef main() -> int:\n    print_header("AUTOM-GAMIT DATA-FIRST INTERACTIVE PROGRAM")\n    print("This is a GAMIT-only program. GLOBK/GLORG will be separate.")\n    print("The program first reads RINEX data status, then asks what to keep, exclude, or rename.")\n\n    print_header("BASIC SETTINGS FOR SCAN")\n    rinex_dir = normalize_input_path(ask_input("Path to local/source RINEX files", "/home/geodesy/Documents/cors-rinex"))\n    year = ask_input("Year", "2026").strip()\n    yy = year[-2:]\n    start_doy = norm_doy(ask_input("Start DOY to inspect/process", "091"))\n    inspect_days = ask_input("Number of days to inspect in RINEX table", "5").strip()\n    expt = ask_input("GAMIT experiment code, 4 characters", "cors").lower().strip()\n    project = ask_input("Project folder name", "cors2026").strip()\n\n    try:\n        expected_doys = expected_doy_list(start_doy, inspect_days)\n    except Exception:\n        print_error("Invalid START_DOY or number of days.")\n        return 1\n\n    print_header("READING LOCAL RINEX BEFORE ANY DECISION")\n    print_info(f"Looking in: {rinex_dir}")\n    print_info(f"Year suffix: {yy}")\n    stations, info = scan_rinex_files(rinex_dir, yy)\n    if not stations:\n        print_error(f"No RINEX observation files found in {rinex_dir} for year suffix {yy}")\n        print_info(f"Expected short-name examples: abcd0910.{yy}o, abcd0910.{yy}o.gz, abcd0910.{yy}d.gz")\n        return 1\n\n    show_station_summary(info)\n    show_data_decision_table(info, expected_doys, yy)\n    station_detail_loop(info)\n\n    source_sites, exclude_sites = ask_source_station_selection(stations, info, expected_doys, yy)\n    ref_frame, apr_file, custom_apr_file = choose_reference_frame_and_apr()\n    local_sites, rename_site, rename_pairs_str, conflict_site = ask_rename_pairs_data_first(source_sites, apr_file)\n\n    print_header("IGS / REFERENCE STATIONS")\n    igs_default = "badg bhr4 daej dgar djig iisc mal2 ntus pol2 reun xmis"\n    igs_sites = norm_sites(ask_input("IGS/reference stations", igs_default))\n\n    print_header("PROCESSING DAYS")\n    if ask_yes_no("Process only ONE day first for testing?", "yes"):\n        ndays = "1"\n    else:\n        ndays = ask_input("Number of days to process", inspect_days).strip()\n\n    print_header("RUN MODE")\n    print_info("Products and IGS RINEX are prepared before sh_gamit.")\n    print_info("sh_gamit itself will be run with -noftp to prevent internal FTP/CDDIS loops.")\n    fresh_start = "YES" if ask_yes_no("Fresh project? YES backs up old project folder", "no") else "NO"\n    download_igs = "YES" if ask_yes_no("Download/check IGS RINEX automatically?", "yes") else "NO"\n    noftp_flag = "-noftp" if ask_yes_no("Strict offline mode? YES means do not download missing products/RINEX/OTL", "no") else ""\n\n    settings = {\n        "PROJECT": project,\n        "EXPT": expt,\n        "YEAR": year,\n        "YY": yy,\n        "START_DOY": start_doy,\n        "NDAYS": ndays,\n        "SOURCE_RINEX_DIR": rinex_dir,\n        "LOCAL_SITES": local_sites,\n        "IGS_SITES": igs_sites,\n        "EXCLUDE_SITES": exclude_sites,\n        "RENAME_SITE": rename_site,\n        "RENAME_PAIRS": rename_pairs_str,\n        "CONFLICT_SITE": conflict_site,\n        "REF_FRAME": ref_frame,\n        "APR_FILE": apr_file,\n        "CUSTOM_APR_FILE": custom_apr_file,\n        "NOFTP_FLAG": noftp_flag,\n        "FRESH_START": fresh_start,\n        "DOWNLOAD_GLOBAL_RINEX": download_igs,\n        "STRICT_NOFTP_CHECK": "YES",\n    }\n\n    os.environ["INTEGRATED_PROJECT_DIR"] = str(Path.home() / project)\n\n    print_header("FINAL PROCESSING SUMMARY")\n    for k in [\n        "PROJECT", "EXPT", "YEAR", "START_DOY", "NDAYS", "SOURCE_RINEX_DIR",\n        "LOCAL_SITES", "EXCLUDE_SITES", "RENAME_SITE", "RENAME_PAIRS",\n        "CONFLICT_SITE", "IGS_SITES", "REF_FRAME", "APR_FILE", "CUSTOM_APR_FILE",\n        "FRESH_START", "NOFTP_FLAG", "DOWNLOAD_GLOBAL_RINEX",\n    ]:\n        print(f"{k:24s}: {settings.get(k, \'\')}")\n\n    if not validate_settings(settings):\n        print_error("Settings are not valid. Restart and correct the values.")\n        return 1\n\n    if not ask_yes_no("Proceed with these settings?", "yes"):\n        print_warning("Stopped before processing.")\n        return 0\n\n    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")\n    log_dir = Path.home() / f"{project}_interactive_logs_{timestamp}"\n    log_dir.mkdir(parents=True, exist_ok=True)\n\n    print_header("PROCESSING STARTED")\n    print_info(f"Logs folder: {log_dir}")\n\n    run_critical("01_check_tools", get_check_tools_step(), settings, log_dir)\n    run_critical("02_auth", get_auth_step(), settings, log_dir)\n    run_critical("03_create_project", get_create_project_step(), settings, log_dir)\n    run_critical("04_copy_rinex", get_copy_rinex_step(), settings, log_dir)\n    run_critical("05_exclude_unselected_source_stations", get_exclude_step(), settings, log_dir, allow_continue=True)\n    run_critical("06_rename_selected_source_stations", get_rename_step(), settings, log_dir, allow_continue=True)\n    run_critical("07_sh_setup", get_sh_setup_step(), settings, log_dir)\n    run_critical("08_apr", get_apr_step(), settings, log_dir)\n    run_critical("09_sites_defaults", get_sites_defaults_step(), settings, log_dir)\n    run_critical("10_lfile", get_lfile_step(), settings, log_dir)\n    run_critical("11_station_info", get_station_info_step(), settings, log_dir)\n    run_critical("12_otl", get_otl_step(), settings, log_dir)\n\n    doy_list = expected_doy_list(start_doy, ndays)\n    for doy in doy_list:\n        print_header(f"DAILY PROCESSING DOY {doy}")\n        run_critical(f"13_products_{doy}", get_product_step(doy), settings, log_dir)\n        run_critical(f"14_global_rinex_{doy}", get_global_rinex_step(doy), settings, log_dir)\n        run_critical(f"15_gamit_{doy}", get_gamit_step(doy), settings, log_dir)\n        run_critical(f"16_qc_{doy}", get_qc_step(doy), settings, log_dir, allow_continue=True)\n\n    print_header("GAMIT PROCESSING COMPLETE")\n    print_success(f"Logs saved in: {log_dir}")\n    print_info("Check h-files in day folders such as 091G/h*.YYDOY.")\n    postprocess_summary(settings, doy_list, log_dir)\n    return 0\n\nif __name__ == "__main__":\n    try:\n        sys.exit(main())\n    except KeyboardInterrupt:\n        print("\\nUser stopped the program.")\n        sys.exit(130)\n'

GLOBK_SOURCE = '#!/usr/bin/env python3\n"""\nAUTOM-GLOBK/GLORG - FINAL DASHBOARD SCRIPT\nBased on the successful globkg2.py patching logic and globkg3.py result display.\n\nThis script:\n- Processes GAMIT h-files with the same workflow that worked.\n- Produces daily .org files and optionally a combined .org.\n- Extracts final coordinates, uncertainties, and POS statistics.\n- Saves CSV, PNG plots, and shows a results dashboard.\n\nUsage:\n    python3 globk_final_dashboard.py\n"""\n\nfrom __future__ import annotations\n\nimport os\nimport re\nimport shlex\nimport shutil\nimport subprocess\nimport sys\nfrom datetime import datetime, date, timedelta\nfrom pathlib import Path\nfrom typing import Dict, List, Optional, Tuple\n\n\n# =============================================================================\n# COLORS AND HELPERS\n# =============================================================================\n\nclass Colors:\n    RED = "\\033[91m"\n    GREEN = "\\033[92m"\n    YELLOW = "\\033[93m"\n    BLUE = "\\033[94m"\n    MAGENTA = "\\033[95m"\n    CYAN = "\\033[96m"\n    BOLD = "\\033[1m"\n    END = "\\033[0m"\n\n\ndef ctext(text: str, color: str) -> str:\n    return f"{color}{text}{Colors.END}"\n\n\ndef print_header(text: str) -> None:\n    print()\n    print(ctext("=" * 90, Colors.CYAN))\n    print(ctext(f"{text:^90}", Colors.CYAN + Colors.BOLD))\n    print(ctext("=" * 90, Colors.CYAN))\n\n\ndef print_info(text: str) -> None:\n    print(ctext(f"i  {text}", Colors.BLUE))\n\n\ndef print_success(text: str) -> None:\n    print(ctext(f"OK {text}", Colors.GREEN))\n\n\ndef print_warning(text: str) -> None:\n    print(ctext(f"WARNING {text}", Colors.YELLOW))\n\n\ndef print_error(text: str) -> None:\n    print(ctext(f"ERROR {text}", Colors.RED))\n\n\ndef print_progress(text: str) -> None:\n    print(ctext(f">> {text}", Colors.MAGENTA))\n\n\ndef ask_input(prompt: str, default: str = "") -> str:\n    if default:\n        ans = input(ctext(f"{prompt} [{default}]: ", Colors.CYAN)).strip()\n        return ans if ans else default\n    return input(ctext(f"{prompt}: ", Colors.CYAN)).strip()\n\n\ndef ask_yes_no(question: str, default: str = "yes") -> bool:\n    default = default.lower().strip()\n    prompt = "[Y/n]" if default == "yes" else "[y/N]"\n    while True:\n        ans = input(ctext(f"{question} {prompt}: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            return default == "yes"\n        if ans in ("y", "yes"):\n            return True\n        if ans in ("n", "no"):\n            return False\n        print("Please answer yes or no.")\n\n\ndef ask_choice(question: str, options: List[str], default: int = 0) -> int:\n    print(ctext(question, Colors.CYAN))\n    for i, opt in enumerate(options, 1):\n        marker = " [default]" if i - 1 == default else ""\n        print(f"  {i}. {opt}{marker}")\n    while True:\n        ans = input(ctext(f"Enter choice (1-{len(options)}) [{default + 1}]: ", Colors.CYAN)).strip()\n        if ans == "":\n            return default\n        if ans.isdigit() and 1 <= int(ans) <= len(options):\n            return int(ans) - 1\n        print(f"Please enter a number from 1 to {len(options)}.")\n\n\ndef normalize_path(text: str) -> Path:\n    text = text.strip().strip(\'"\').strip("\'")\n    if text.startswith("home/"):\n        text = "/" + text\n    return Path(os.path.expandvars(text)).expanduser()\n\n\ndef timestamp() -> str:\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\n\ndef command_exists(cmd: str) -> bool:\n    return shutil.which(cmd) is not None\n\n\ndef read_text_safe(path: Path, max_bytes: Optional[int] = None) -> str:\n    try:\n        if max_bytes is None:\n            return path.read_text(errors="ignore")\n        with open(path, "rb") as f:\n            data = f.read(max_bytes)\n        return data.decode(errors="ignore")\n    except Exception:\n        return ""\n\n\ndef backup_file(path: Path, tag: str) -> Optional[Path]:\n    if not path.is_file():\n        return None\n    b = path.with_name(f"{path.name}.before_{tag}_{timestamp()}")\n    shutil.copy2(path, b)\n    return b\n\n\ndef path_for_cmd(path: Path) -> str:\n    try:\n        return str(path.expanduser().resolve())\n    except Exception:\n        return str(path.expanduser())\n\n\ndef yy_to_full_year(yy: str) -> str:\n    n = int(yy)\n    if n >= 80:\n        return f"19{yy}"\n    return f"20{yy}"\n\n\ndef shell_quote(value: object) -> str:\n    return shlex.quote(str(value))\n\n\n# =============================================================================\n# H-FILE DETECTION\n# =============================================================================\n\nHFILE_RE = re.compile(r"^h([A-Za-z0-9]{4})([A-Za-z0-9])\\.(\\d{2})(\\d{3})$")\n\n\ndef parse_hfile_name(path: Path) -> Optional[Dict[str, str]]:\n    m = HFILE_RE.match(path.name)\n    if not m:\n        return None\n    expt, soln_letter, yy, doy = m.groups()\n    return {\n        "expt": expt.lower(),\n        "soln_letter": soln_letter.lower(),\n        "yy": yy,\n        "doy": doy,\n    }\n\n\ndef scan_hfiles(project_dir: Path) -> Dict[str, Dict]:\n    results: Dict[str, Dict] = {}\n    day_pattern = re.compile(r"^(\\d{3})([A-Za-z])$")\n\n    for item in sorted(project_dir.iterdir()):\n        if not item.is_dir():\n            continue\n\n        m = day_pattern.match(item.name)\n        if not m:\n            continue\n\n        folder_doy, netext = m.groups()\n        valid_hfiles = []\n        valid_infos = []\n\n        for p in sorted(item.iterdir()):\n            if not p.is_file() or p.stat().st_size <= 0:\n                continue\n\n            info = parse_hfile_name(p)\n            if not info:\n                continue\n\n            if info["doy"] != folder_doy:\n                print_warning(f"Skipping mismatched h-file: {p.name} inside {item.name}")\n                continue\n\n            valid_hfiles.append(p)\n            valid_infos.append(info)\n\n        if valid_hfiles:\n            info0 = valid_infos[0]\n            results[folder_doy] = {\n                "netext": netext,\n                "hfiles": valid_hfiles,\n                "expt": info0["expt"],\n                "yy": info0["yy"],\n                "soln_letter": info0["soln_letter"],\n            }\n\n    return results\n\n\ndef select_processing_range(scan_results: Dict[str, Dict]) -> Dict[str, Dict]:\n    all_doys = sorted(scan_results.keys())\n    print_header("AVAILABLE H-FILE DAYS")\n    print_info("Available DOYs: " + " ".join(all_doys))\n\n    if ask_yes_no("Process all available h-file days?", "yes"):\n        selected_doys = all_doys\n    else:\n        start_doy = ask_input("Start DOY", all_doys[0]).strip().zfill(3)\n        end_doy = ask_input("End DOY", all_doys[-1]).strip().zfill(3)\n\n        if not (start_doy.isdigit() and end_doy.isdigit()):\n            print_error("Start and end DOY must be numeric.")\n            sys.exit(1)\n\n        if int(start_doy) > int(end_doy):\n            print_error("Start DOY cannot be greater than End DOY.")\n            sys.exit(1)\n\n        selected_doys = [f"{d:03d}" for d in range(int(start_doy), int(end_doy) + 1)]\n\n    missing = [d for d in selected_doys if d not in scan_results]\n    if missing:\n        print_error("Missing h-files for selected DOYs: " + " ".join(missing))\n        sys.exit(1)\n\n    print_success("Selected DOYs: " + " ".join(selected_doys))\n    return {d: scan_results[d] for d in selected_doys}\n\n\ndef check_scan_consistency(scan_results: Dict[str, Dict]) -> bool:\n    yy_set = sorted({d["yy"] for d in scan_results.values()})\n    expt_set = sorted({d["expt"] for d in scan_results.values()})\n    netext_set = sorted({d["netext"] for d in scan_results.values()})\n\n    ok = True\n    if len(yy_set) != 1:\n        print_error("Mixed year suffixes: " + " ".join(yy_set))\n        ok = False\n\n    if len(expt_set) != 1:\n        print_error("Mixed experiment codes: " + " ".join(expt_set))\n        ok = False\n\n    if len(netext_set) != 1:\n        print_error("Mixed network extensions: " + " ".join(netext_set))\n        ok = False\n\n    if ok:\n        print_success("H-file settings are consistent.")\n\n    return ok\n\n\ndef detect_settings(scan_results: Dict[str, Dict]) -> Tuple[str, str, str, str, str, str, List[str]]:\n    doys = sorted(scan_results.keys())\n    if not doys:\n        return "", "", "", "", "", "", []\n\n    expt_counts: Dict[str, int] = {}\n    netext_counts: Dict[str, int] = {}\n    yy_set = set()\n\n    for d in scan_results.values():\n        expt_counts[d["expt"]] = expt_counts.get(d["expt"], 0) + 1\n        netext_counts[d["netext"]] = netext_counts.get(d["netext"], 0) + 1\n        yy_set.add(d["yy"])\n\n    expt = sorted(expt_counts.items(), key=lambda x: x[1], reverse=True)[0][0]\n    netext = sorted(netext_counts.items(), key=lambda x: x[1], reverse=True)[0][0]\n    yy = sorted(yy_set)[0]\n    year = yy_to_full_year(yy)\n\n    return year, doys[0], doys[-1], str(len(doys)), expt, netext, doys\n\n\ndef show_detected_settings(\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    ndays: str,\n    expt: str,\n    netext: str,\n    doys: List[str],\n) -> None:\n    print_header("DETECTED SETTINGS")\n    print(f"{\'Year\':20s}: {year}")\n    print(f"{\'Start DOY\':20s}: {start_doy}")\n    print(f"{\'End DOY\':20s}: {end_doy}")\n    print(f"{\'Number of days\':20s}: {ndays}")\n    print(f"{\'Experiment code\':20s}: {expt}")\n    print(f"{\'Network extension\':20s}: {netext}")\n    print(f"{\'DOY list\':20s}: {\' \'.join(doys)}")\n\n\n# =============================================================================\n# DETECT GAMIT/GLOBK INSTALLATION\n# =============================================================================\n\ndef detect_gamit_paths(project_dir: Path) -> Dict[str, List[Path]]:\n    paths: Dict[str, List[Path]] = {"table_dirs": []}\n\n    def add_dir(p: Path) -> None:\n        p = p.expanduser().resolve()\n        if p.is_dir() and p not in paths["table_dirs"]:\n            paths["table_dirs"].append(p)\n\n    add_dir(project_dir / "tables")\n\n    for env in ["GG_TABLES", "GAMIT_TABLES"]:\n        val = os.environ.get(env, "").strip()\n        if val:\n            add_dir(Path(val).expanduser())\n\n    sh = shutil.which("sh_glred")\n    if sh:\n        p = Path(sh).resolve()\n        if p.parent.name in ["com", "bin"]:\n            add_dir(p.parent.parent / "tables")\n\n    for d in [\n        Path.home() / "gg" / "tables",\n        Path.home() / "GAMIT_GLOBK" / "tables",\n    ]:\n        add_dir(d)\n\n    return paths\n\n\n# =============================================================================\n# APR FIXES AND CHECKS\n# =============================================================================\n\n\ndef ensure_custom_apr_exists(project_dir: Path) -> bool:\n    """Check that a usable project APR exists. Supports custom_igs20/custom_igs14/custom_itrf08."""\n    p = choose_apr_file(project_dir)\n    if p and p.is_file():\n        print_success(f"Usable APR found: {p}")\n        return True\n    print_error("No usable APR found in project tables or process.defaults.")\n    print_error("Run the GAMIT part first or create a custom APR from a proper base frame APR.")\n    return False\n\n\ndef ensure_local_stations_in_apr(apr_file: Path, project_dir: Path, local_stations: List[str]) -> bool:\n    """Append missing local stations from lfile. to the selected APR file."""\n    lfile = project_dir / "tables" / "lfile."\n\n    if not apr_file.is_file():\n        print_error(f"APR file not found. Cannot append local stations: {apr_file}")\n        return False\n\n    if not lfile.is_file():\n        print_warning("lfile. not found; cannot check local stations.")\n        return True\n\n    backup_file(apr_file, "apr_before_local_station_append")\n\n    local_names = [st.upper().replace("_GPS", "") + "_GPS" for st in local_stations]\n    apr_stations = set()\n\n    with open(apr_file, "r", errors="ignore") as f:\n        for line in f:\n            parts = line.split()\n            if parts:\n                apr_stations.add(parts[0].upper())\n\n    missing = [name for name in local_names if name not in apr_stations]\n\n    if not missing:\n        print_success("All local stations already present in selected APR.")\n        return True\n\n    print_warning("Local stations missing from selected APR: " + " ".join(missing))\n\n    with open(lfile, "r", errors="ignore") as f:\n        lines = f.readlines()\n\n    missing_set = set(missing)\n    added_names = set()\n\n    with open(apr_file, "a", encoding="utf-8", errors="ignore") as f:\n        if not read_text_safe(apr_file).endswith("\\n"):\n            f.write("\\n")\n\n        for line in lines:\n            parts = line.split()\n            if not parts:\n                continue\n            name = parts[0].upper()\n            if not name.endswith("_GPS") and len(name) == 4:\n                name = name + "_GPS"\n            if name in missing_set and name not in added_names:\n                # If local APR sigmas are all zero, use 10 m a priori sigma.\n                parts2 = line.split()\n                if len(parts2) >= 7:\n                    try:\n                        if float(parts2[4]) == 0.0 and float(parts2[5]) == 0.0 and float(parts2[6]) == 0.0:\n                            parts2[4] = parts2[5] = parts2[6] = "10.0"\n                            line = " ".join(parts2) + "\\n"\n                    except Exception:\n                        pass\n                f.write(line if line.endswith("\\n") else line + "\\n")\n                added_names.add(name)\n\n    still_missing = sorted(missing_set - added_names)\n    if added_names:\n        print_success(f"Added {len(added_names)} station(s) to selected APR from lfile.: {\' \'.join(sorted(added_names))}")\n    if still_missing:\n        print_error("These stations were not found in lfile.: " + " ".join(still_missing))\n        return False\n    return True\n\n\ndef fix_zero_sigmas_in_apr(apr_file: Path, local_stations: List[str]) -> None:\n    """Replace zero sigmas with 10.0 for local stations in the selected APR file."""\n    if not apr_file.is_file():\n        return\n\n    backup_file(apr_file, "apr_before_zero_sigma_fix")\n    local_upper = {st.upper().replace("_GPS", "") for st in local_stations}\n\n    with open(apr_file, "r", errors="ignore") as f:\n        lines = f.readlines()\n\n    new_lines = []\n    for line in lines:\n        parts = line.split()\n        if not parts:\n            new_lines.append(line)\n            continue\n        name = parts[0].upper()\n        code4 = name.replace("_GPS", "")\n        if name.endswith("_GPS") and code4 in local_upper and len(parts) >= 7:\n            try:\n                sig1 = float(parts[4])\n                sig2 = float(parts[5])\n                sig3 = float(parts[6])\n                if sig1 == 0.0 and sig2 == 0.0 and sig3 == 0.0:\n                    parts[4] = "10.0"\n                    parts[5] = "10.0"\n                    parts[6] = "10.0"\n                    line = " ".join(parts) + "\\n"\n                    print_warning(f"Replaced zero sigmas for {name} with 10.0")\n            except ValueError:\n                pass\n        new_lines.append(line)\n\n    with open(apr_file, "w", encoding="utf-8", errors="ignore") as f:\n        f.writelines(new_lines)\n\ndef check_sites_exist_in_apr(apr_path: Path, sites: List[str], label: str) -> bool:\n    """Check whether site codes exist in APR as SITE_GPS."""\n    text = read_text_safe(apr_path, max_bytes=50_000_000).upper()\n    missing = []\n\n    for site in sites:\n        token = site.upper()\n        if not token.endswith("_GPS"):\n            token = token + "_GPS"\n        if token not in text:\n            missing.append(token)\n\n    if missing:\n        print_warning(f"{label} missing from APR: {\' \'.join(missing)}")\n        return False\n\n    print_success(f"All {label} found in APR.")\n    return True\n\n\n# =============================================================================\n# COMMAND FILE REGENERATION AND PATCHING (Working globkg2.py logic)\n# =============================================================================\n\ndef regenerate_command_files(project_dir: Path) -> bool:\n    """Use sh_glred -cmd to create fresh command files compatible with installed version."""\n    print_progress("Regenerating command files with sh_glred -cmd")\n\n    log_dir = project_dir / "globk_glorg_logs"\n    log_dir.mkdir(exist_ok=True)\n    log_path = log_dir / "sh_glred_cmd.log"\n\n    cmd = ["sh_glred", "-cmd"]\n\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.run(\n                cmd,\n                cwd=str(project_dir),\n                stdout=f,\n                stderr=subprocess.STDOUT,\n                text=True,\n                timeout=120,\n            )\n\n        if proc.returncode == 0:\n            print_success("Command files regenerated successfully.")\n            gsoln = project_dir / "gsoln"\n            tables = project_dir / "tables"\n            tables.mkdir(exist_ok=True)\n\n            for fname in ["globk.cmd", "glorg.cmd"]:\n                src = gsoln / fname\n                dst = tables / fname\n                if src.is_file():\n                    shutil.copy2(src, dst)\n                    print_success(f"Copied {fname} to tables/")\n                else:\n                    print_warning(f"{fname} was not found in gsoln/ after sh_glred -cmd")\n\n            return True\n\n        print_warning(f"sh_glred -cmd returned {proc.returncode}. Check log: {log_path}")\n        return False\n\n    except Exception as e:\n        print_error(f"Error during regeneration: {e}")\n        return False\n\n\ndef remove_auto_blocks(text: str) -> str:\n    """Remove old auto-generated blocks."""\n    text = re.sub(\n        r"\\n?\\* --- BEGIN AUTO GLOBK/GLORG FRAME BLOCK ---\\n.*?\\n\\* --- END AUTO GLOBK/GLORG FRAME BLOCK ---\\n?",\n        "\\n",\n        text,\n        flags=re.DOTALL,\n    )\n    return text\n\n\ndef patch_globk_glorg(project_dir: Path, apr_path: Path, eq_path: Optional[Path], stab_sites: List[str]) -> None:\n    """\n    Patch globk.cmd and glorg.cmd using the same simple command style that worked\n    in the user\'s successful globkg2.py run.\n\n    Important:\n    - No leading spaces before active command names.\n    - org is lowercase in org_opt.\n    - Do not force apr_site all ...\n    - Do not aggressively comment/clean old template lines.\n    """\n    tables = project_dir / "tables"\n\n    for fname in ["globk.cmd", "glorg.cmd"]:\n        p = tables / fname\n        if not p.is_file():\n            alt = project_dir / "gsoln" / fname\n            if alt.is_file():\n                shutil.copy2(alt, p)\n            else:\n                print_error(f"Missing {fname}; cannot patch.")\n                sys.exit(1)\n\n    backup_file(tables / "globk.cmd", "pre_patch")\n    backup_file(tables / "glorg.cmd", "pre_patch")\n\n    globk_text = read_text_safe(tables / "globk.cmd")\n    glorg_text = read_text_safe(tables / "glorg.cmd")\n\n    globk_text = remove_auto_blocks(globk_text)\n    glorg_text = remove_auto_blocks(glorg_text)\n\n    # Same working behavior as globkg2.py.\n    if re.search(r"^\\s*org_opt\\b", globk_text, re.MULTILINE):\n        globk_text = re.sub(\n            r"^\\s*org_opt\\b.*$",\n            "org_opt PSUM GDLF CMDS org",\n            globk_text,\n            flags=re.MULTILINE,\n        )\n    else:\n        globk_text = re.sub(\n            r"^apr_file\\b.*$",\n            r"\\g<0>\\norg_opt PSUM GDLF CMDS org",\n            globk_text,\n            flags=re.MULTILINE,\n        )\n\n    if not re.search(r"^\\s*prt_opt\\b", globk_text, re.MULTILINE):\n        globk_text += "\\nprt_opt NOPR\\n"\n\n    if not re.search(r"^\\s*org_cmd\\b", globk_text, re.MULTILINE):\n        globk_text += "\\norg_cmd glorg.cmd\\n"\n\n    block_globk = (\n        "\\n* --- BEGIN AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n        f"* Added by {Path(__file__).name} on {timestamp()}\\n"\n        "* Frame settings\\n"\n    )\n    if eq_path:\n        # Keep eq optional. In the successful run EQ was not used.\n        block_globk += f"eq_file {path_for_cmd(eq_path)}\\n"\n    block_globk += f"apr_file {path_for_cmd(apr_path)}\\n"\n    block_globk += "org_cmd glorg.cmd\\n"\n    block_globk += "org_opt PSUM GDLF CMDS org\\n"\n    block_globk += "prt_opt NOPR\\n"\n    block_globk += "* --- END AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n\n    block_glorg = (\n        "\\n* --- BEGIN AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n        f"* Added by {Path(__file__).name} on {timestamp()}\\n"\n        "* Frame settings\\n"\n    )\n    block_glorg += f"apr_file {path_for_cmd(apr_path)}\\n"\n    block_glorg += "stab_site clear\\n"\n    if stab_sites:\n        block_glorg += "stab_site " + " ".join(stab_sites) + "\\n"\n    block_glorg += "pos_org xtran ytran ztran xrot yrot zrot\\n"\n    block_glorg += "* --- END AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n\n    globk_text += block_globk\n    glorg_text += block_glorg\n\n    (tables / "globk.cmd").write_text(globk_text)\n    (tables / "glorg.cmd").write_text(glorg_text)\n\n    gsoln = project_dir / "gsoln"\n    gsoln.mkdir(exist_ok=True)\n    shutil.copy2(tables / "globk.cmd", gsoln / "globk.cmd")\n    shutil.copy2(tables / "glorg.cmd", gsoln / "glorg.cmd")\n\n    print_success("Patched command files and copied to gsoln/.")\n\n\n# =============================================================================\n# RUN SH_GLRED AND VERIFY\n# =============================================================================\n\ndef run_sh_glred(\n    project_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    netext: str,\n    options: str,\n    log_dir: Path,\n) -> int:\n    opt_tokens = options.split()\n\n    cmd = [\n        "sh_glred",\n        "-s",\n        year,\n        start_doy,\n        year,\n        end_doy,\n        "-expt",\n        expt,\n        "-netext",\n        netext,\n        "-opt",\n    ] + opt_tokens\n\n    log_path = log_dir / f"sh_glred_{start_doy}_{end_doy}.log"\n\n    print_progress("Running: " + " ".join(cmd))\n    print_info(f"Log file: {log_path}")\n\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.Popen(\n                cmd,\n                cwd=str(project_dir),\n                stdout=subprocess.PIPE,\n                stderr=subprocess.STDOUT,\n                text=True,\n                bufsize=1,\n            )\n\n            assert proc.stdout is not None\n            for line in proc.stdout:\n                print(line, end="")\n                f.write(line)\n\n            rc = proc.wait()\n\n        print_info(f"Return code: {rc}")\n        return rc\n\n    except Exception as e:\n        print_error(f"Exception: {e}")\n        return 1\n\n\ndef run_combined_survey(\n    project_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    netext: str,\n    ndays: int,\n    log_dir: Path,\n) -> int:\n    cmd = [\n        "sh_glred",\n        "-s",\n        year,\n        start_doy,\n        year,\n        end_doy,\n        "-expt",\n        expt,\n        "-netext",\n        netext,\n        "-globk_cmd_prefix",\n        "COMB",\n        "-opt",\n        "G",\n        "-ncomb",\n        str(ndays),\n    ]\n\n    log_path = log_dir / f"sh_glred_combined_{start_doy}_{end_doy}.log"\n\n    print_progress("Running: " + " ".join(cmd))\n    print_info(f"Log file: {log_path}")\n\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.Popen(\n                cmd,\n                cwd=str(project_dir),\n                stdout=subprocess.PIPE,\n                stderr=subprocess.STDOUT,\n                text=True,\n                bufsize=1,\n            )\n\n            assert proc.stdout is not None\n            for line in proc.stdout:\n                print(line, end="")\n                f.write(line)\n\n            rc = proc.wait()\n\n        print_info(f"Return code: {rc}")\n        return rc\n\n    except Exception as e:\n        print_error(f"Exception during combined survey: {e}")\n        return 1\n\n\ndef verify_org_files(project_dir: Path, expt: str, yy: str, doys: List[str]) -> List[Path]:\n    """Return list of existing daily .org files using correct pattern globk_<expt>_<yy><doy>.org."""\n    orgs: List[Path] = []\n    gsoln = project_dir / "gsoln"\n\n    for doy in doys:\n        expected = gsoln / f"globk_{expt}_{yy}{doy}.org"\n        if expected.is_file() and expected.stat().st_size > 0:\n            orgs.append(expected)\n\n    return orgs\n\n\ndef find_combined_org(project_dir: Path, expt: str, yy: str, start_doy: str, end_doy: str) -> List[Path]:\n    """Find combined .org file."""\n    gsoln = project_dir / "gsoln"\n    expected = gsoln / f"globk_{expt}_{yy}{start_doy}_{yy}{end_doy}.org"\n\n    if expected.is_file() and expected.stat().st_size > 0:\n        return [expected]\n\n    return sorted(gsoln.glob(f"*{expt}*{yy}{start_doy}*{yy}{end_doy}*.org"))\n\n\n# =============================================================================\n# FRAME SELECTION\n# =============================================================================\n\ndef detect_frame_family_from_apr(apr_path: Optional[Path]) -> str:\n    if apr_path is None:\n        return "Unknown"\n\n    text = read_text_safe(apr_path, max_bytes=200_000)\n    if text:\n        t = text.lower()\n        if "itrf20" in t or "igs20" in t or "igb20" in t or "itrf2020" in t:\n            return "IGS20"\n        if "itrf14" in t or "igs14" in t or "igb14" in t or "itrf2014" in t:\n            return "IGS14"\n        if "itrf08" in t or "igs08" in t or "igb08" in t or "itrf2008" in t:\n            return "ITRF08"\n\n    name = apr_path.name.lower()\n    if "igs20" in name or "igb20" in name or "itrf20" in name:\n        return "IGS20"\n    if "igs14" in name or "igb14" in name or "itrf14" in name:\n        return "IGS14"\n    if "igs08" in name or "igb08" in name or "itrf08" in name or "custom_itrf08" in name or "all_pbo_igs08" in name:\n        return "ITRF08"\n\n    return "Unknown"\n\n\ndef find_frame_files(project_dir: Path, frame: str) -> Tuple[Optional[Path], Optional[Path]]:\n    detected = detect_gamit_paths(project_dir)\n    search_dirs = detected["table_dirs"]\n\n    if frame.upper() == "IGS20":\n        apr_candidates = ["igs20.apr", "igb20_comb.apr", "igb20.apr", "itrf20.apr"]\n        eq_candidates = ["igs20.eq", "igb20_comb.eq", "igb20.eq", "itrf20.eq", "All_PBO.eq"]\n    elif frame.upper() == "IGS14":\n        apr_candidates = ["igs14_comb.apr", "igs14.apr", "igb14_comb.apr", "igb14.apr", "itrf14.apr"]\n        eq_candidates = ["igs14_comb.eq", "igs14.eq", "igb14_comb.eq", "igb14.eq", "itrf14.eq", "All_PBO.eq"]\n    elif frame.upper() == "ITRF08":\n        apr_candidates = [\n            "custom_itrf08.apr",\n            "All_PBO_igs08.apr",\n            "itrf08_comb.apr",\n            "itrf08.apr",\n            "igb08_comb.apr",\n            "igb08.apr",\n            "igs08.apr",\n        ]\n        eq_candidates = ["All_PBO.eq", "itrf08_comb.eq", "itrf08.eq", "igb08_comb.eq", "igb08.eq", "igs08.eq"]\n    else:\n        return None, None\n\n    apr_path = None\n\n    for d in search_dirs:\n        for name in apr_candidates:\n            p = d / name\n            if p.is_file():\n                apr_path = p\n                break\n        if apr_path:\n            break\n\n    if not apr_path:\n        return None, None\n\n    eq_path = None\n    for d in search_dirs:\n        for name in eq_candidates:\n            p = d / name\n            if p.is_file():\n                eq_path = p\n                break\n        if eq_path:\n            break\n\n    return apr_path, eq_path\n\n\n\ndef apr_family_from_name(apr_file: str) -> str:\n    name = Path(apr_file).name.lower()\n    if any(tok in name for tok in ["igs20", "igb20", "igc20", "itrf20", "custom_igs20"]):\n        return "IGS20"\n    if any(tok in name for tok in ["igs14", "igb14", "itrf14", "all_pbo_igs14", "custom_igs14"]):\n        return "IGS14"\n    if any(tok in name for tok in ["igs08", "igb08", "itrf08", "all_pbo_igs08", "custom_itrf08"]):\n        return "ITRF08"\n    return "Unknown"\n\n\ndef parse_aprf_from_process_defaults(project_dir: Path) -> Optional[Path]:\n    defaults = project_dir / "tables" / "process.defaults"\n    if not defaults.is_file():\n        return None\n    text = read_text_safe(defaults)\n    m = re.search(r"^\\s*set\\s+aprf\\s*=\\s*(\\S+)", text, re.I | re.M)\n    if not m:\n        m = re.search(r"^\\s*apr_file\\s+(\\S+)", text, re.I | re.M)\n    if not m:\n        return None\n    token = m.group(1).strip().strip(\'"\').strip("\'")\n    candidates = []\n    p = Path(token).expanduser()\n    if p.is_absolute():\n        candidates.append(p)\n    candidates.append(project_dir / "tables" / token)\n    candidates.append(project_dir / token)\n    for d in detect_gamit_paths(project_dir)["table_dirs"]:\n        candidates.append(d / token)\n    for p in candidates:\n        if p.is_file():\n            return p\n    return None\n\n\ndef choose_apr_file(project_dir: Path) -> Optional[Path]:\n    tables = project_dir / "tables"\n\n    # First priority: the exact APR selected by the GAMIT part in process.defaults.\n    p = parse_aprf_from_process_defaults(project_dir)\n    if p and p.is_file():\n        return p\n\n    # Next priority: any custom APR created by the GAMIT part.\n    if tables.is_dir():\n        for name in ["custom_igs20.apr", "custom_igs14.apr", "custom_itrf08.apr"]:\n            p = tables / name\n            if p.is_file():\n                return p\n\n        # Then common frame APRs in project tables.\n        for name in ["igb20_comb.apr", "igs20.apr", "igs14_comb.apr", "igb14_comb.apr", "All_PBO_igs08.apr", "itrf08.apr"]:\n            p = tables / name\n            if p.is_file():\n                return p\n\n    return None\n\n\ndef eq_family_from_name(eq_file: str) -> str:\n    """Return a simple frame/family hint from an EQ filename."""\n    name = Path(eq_file).name.lower()\n    if any(tok in name for tok in ["igs20", "igb20", "igc20", "itrf20"]):\n        return "IGS20"\n    if any(tok in name for tok in ["igs14", "igb14", "itrf14"]):\n        return "IGS14"\n    if any(tok in name for tok in ["igs08", "igb08", "itrf08"]):\n        return "ITRF08"\n    if "pbo" in name:\n        return "PBO/general"\n    return "Unknown"\n\n\ndef collect_table_files(project_dir: Path, extension: str) -> List[Path]:\n    """Collect APR/EQ files from project tables and GAMIT/GLOBK table folders."""\n    detected = detect_gamit_paths(project_dir)\n    dirs: List[Path] = []\n\n    for d in [project_dir / "tables", project_dir]:\n        try:\n            if d.is_dir() and d.resolve() not in [x.resolve() for x in dirs]:\n                dirs.append(d)\n        except Exception:\n            pass\n\n    for d in detected.get("table_dirs", []):\n        try:\n            if d.is_dir() and d.resolve() not in [x.resolve() for x in dirs]:\n                dirs.append(d)\n        except Exception:\n            pass\n\n    for d in [Path.home() / "gg" / "tables", Path.home() / "GAMIT_GLOBK" / "tables"]:\n        try:\n            if d.is_dir() and d.resolve() not in [x.resolve() for x in dirs]:\n                dirs.append(d)\n        except Exception:\n            pass\n\n    files: List[Path] = []\n    seen = set()\n    for d in dirs:\n        for p in sorted(d.glob(f"*{extension}")):\n            try:\n                rp = p.resolve()\n            except Exception:\n                rp = p\n            if p.is_file() and str(rp) not in seen:\n                files.append(p)\n                seen.add(str(rp))\n    return files\n\n\ndef preferred_eq_names_for_apr(apr_path: Path) -> List[str]:\n    """Recommended EQ file names for the selected APR/frame."""\n    family = detect_frame_family_from_apr(apr_path)\n    base_eq = apr_path.name.replace(".apr", ".eq")\n\n    if family == "IGS20":\n        return [\n            base_eq,\n            "igb20_comb.eq",\n            "itrf20u24.eq",\n            "itrf20u23.eq",\n            "itrf20.eq",\n            "igs20.eq",\n            "igb20.eq",\n            "igc20.eq",\n            "All_PBO.eq",\n        ]\n\n    if family == "IGS14":\n        return [\n            base_eq,\n            "igb14_comb.eq",\n            "igs14_comb.eq",\n            "itrf14.eq",\n            "igb14.eq",\n            "All_PBO.eq",\n        ]\n\n    if family == "ITRF08":\n        return [\n            base_eq,\n            "All_PBO.eq",\n            "All_PBO_eqs.eq",\n            "All_PBO_edits.eq",\n            "igs08.eq",\n            "igb08.eq",\n            "itrf08.eq",\n        ]\n\n    return [base_eq, "All_PBO.eq"]\n\n\ndef choose_eq_file(project_dir: Path, apr: Path) -> Optional[Path]:\n    """\n    Auto EQ selection. First try same-name EQ, then frame-compatible common EQ files.\n    This avoids the earlier situation where custom_itrf08.apr gave no EQ although\n    All_PBO.eq or frame EQ files were available in ~/gg/tables.\n    """\n    eq_files = collect_table_files(project_dir, ".eq")\n    if not eq_files:\n        return None\n\n    preferred = preferred_eq_names_for_apr(apr)\n    for name in preferred:\n        for p in eq_files:\n            if p.name.lower() == name.lower():\n                return p\n\n    return None\n\n\ndef suggest_apr_file(project_dir: Path, apr_files: List[Path]) -> Optional[Path]:\n    """Suggest the project APR already selected by GAMIT, otherwise a custom APR."""\n    auto = choose_apr_file(project_dir)\n    if auto and auto.is_file():\n        for p in apr_files:\n            try:\n                if p.resolve() == auto.resolve():\n                    return p\n            except Exception:\n                if str(p) == str(auto):\n                    return p\n\n    preferred_names = [\n        "custom_igs20.apr",\n        "custom_igs14.apr",\n        "custom_itrf08.apr",\n        "igb20_comb.apr",\n        "igs20.apr",\n        "igs14_comb.apr",\n        "All_PBO_igs08.apr",\n    ]\n    for name in preferred_names:\n        for p in apr_files:\n            if p.name.lower() == name.lower():\n                return p\n    return apr_files[0] if apr_files else None\n\n\ndef suggest_eq_file(project_dir: Path, apr_path: Path, eq_files: List[Path]) -> Optional[Path]:\n    """Suggest a frame-compatible EQ file for the chosen APR."""\n    if not eq_files:\n        return None\n    preferred = preferred_eq_names_for_apr(apr_path)\n    for name in preferred:\n        for p in eq_files:\n            if p.name.lower() == name.lower():\n                return p\n    return eq_files[0]\n\n\ndef show_numbered_file_list(title: str, files: List[Path], suggested: Optional[Path] = None) -> None:\n    """Print APR/EQ files as a numbered list and mark the suggestion."""\n    print_header(title)\n    if not files:\n        print_warning("No files found.")\n        return\n\n    try:\n        suggested_resolved = suggested.resolve() if suggested else None\n    except Exception:\n        suggested_resolved = suggested\n\n    for i, p in enumerate(files, 1):\n        try:\n            same = suggested_resolved is not None and p.resolve() == suggested_resolved\n        except Exception:\n            same = suggested is not None and str(p) == str(suggested)\n\n        family = detect_frame_family_from_apr(p) if p.suffix.lower() == ".apr" else eq_family_from_name(p.name)\n        mark = "  <-- suggested" if same else ""\n        print(f"{i:2d}. {p}    [{family}]{mark}")\n\n\ndef ask_file_from_numbered_list(\n    prompt: str,\n    files: List[Path],\n    suggested: Optional[Path],\n    required: bool = True,\n    allow_none: bool = False,\n) -> Optional[Path]:\n    """\n    Ask user to select a file by number or full path.\n    Empty input uses the suggested file when available.\n    """\n    if suggested:\n        default = str(suggested)\n    elif allow_none and not required:\n        default = "none"\n    else:\n        default = ""\n\n    while True:\n        if default:\n            ans = input(ctext(f"{prompt} [{default}]: ", Colors.CYAN)).strip()\n        else:\n            ans = input(ctext(f"{prompt}: ", Colors.CYAN)).strip()\n\n        if ans == "":\n            if suggested:\n                return suggested\n            if allow_none and not required:\n                return None\n            print_warning("Required. Please enter a list number or full path.")\n            continue\n\n        if allow_none and ans.lower() in ("none", "no", "skip", "0"):\n            return None\n\n        if ans.isdigit():\n            idx = int(ans)\n            if 1 <= idx <= len(files):\n                return files[idx - 1]\n            print_warning(f"Number must be between 1 and {len(files)}.")\n            continue\n\n        p = normalize_path(ans)\n        if p.is_file():\n            return p\n\n        print_warning(f"File not found: {p}")\n\n\ndef ask_manual_apr_eq_files(project_dir: Path) -> Tuple[Path, Optional[Path], str]:\n    """Manual APR/EQ selection with visible lists and suggestions."""\n    apr_files = collect_table_files(project_dir, ".apr")\n    suggested_apr = suggest_apr_file(project_dir, apr_files)\n    show_numbered_file_list("AVAILABLE APR FILES", apr_files, suggested_apr)\n\n    apr_path = ask_file_from_numbered_list(\n        "APR file - enter list number or full path",\n        apr_files,\n        suggested_apr,\n        required=True,\n        allow_none=False,\n    )\n\n    if not apr_path or not apr_path.is_file():\n        print_error("APR file is required.")\n        sys.exit(1)\n\n    frame_name = detect_frame_family_from_apr(apr_path)\n\n    eq_files = collect_table_files(project_dir, ".eq")\n    suggested_eq = suggest_eq_file(project_dir, apr_path, eq_files)\n    show_numbered_file_list("AVAILABLE EQ FILES", eq_files, suggested_eq)\n\n    print_info("EQ file is optional for a short test run, but recommended for final long time-series processing.")\n    eq_path = ask_file_from_numbered_list(\n        "EQ file - enter list number/full path, or type none",\n        eq_files,\n        suggested_eq,\n        required=False,\n        allow_none=True,\n    )\n\n    return apr_path, eq_path, frame_name\n\n\ndef ask_file_path(prompt: str, default: str = "", required: bool = True) -> Optional[Path]:\n    while True:\n        ans = ask_input(prompt, default).strip()\n\n        if ans == "" and not required:\n            return None\n\n        if ans == "" and required:\n            print_warning("Required. Please enter a path.")\n            continue\n\n        p = normalize_path(ans)\n        if p.is_file():\n            return p\n\n        print_warning(f"File not found: {p}")\n        if not required and ask_yes_no("Skip?", "yes"):\n            return None\n\n\ndef select_frame(project_dir: Path) -> Tuple[Path, Optional[Path], str]:\n    print_header("SELECT REFERENCE FRAME")\n    print_info("Choose the reference frame for your final solution.")\n\n    choices = [\n        "IGS20 / ITRF2020",\n        "IGS14 / ITRF2014",\n        "ITRF08 / IGS08",\n        "Auto-detect from existing files",\n        "Manually specify APR and EQ files",\n    ]\n\n    idx = ask_choice("Choose reference frame:", choices, default=3)\n\n    apr_path = None\n    eq_path = None\n    frame_name = ""\n\n    if idx == 0:\n        frame_name = "IGS20"\n        apr_path, eq_path = find_frame_files(project_dir, "IGS20")\n    elif idx == 1:\n        frame_name = "IGS14"\n        apr_path, eq_path = find_frame_files(project_dir, "IGS14")\n    elif idx == 2:\n        frame_name = "ITRF08"\n        apr_path, eq_path = find_frame_files(project_dir, "ITRF08")\n    elif idx == 3:\n        apr_path = choose_apr_file(project_dir)\n        if apr_path:\n            frame_name = detect_frame_family_from_apr(apr_path)\n            eq_path = choose_eq_file(project_dir, apr_path)\n        else:\n            print_warning("Auto-detect failed. Please specify manually.")\n            idx = 4\n\n    if idx == 4 or apr_path is None:\n        apr_path, eq_path, frame_name = ask_manual_apr_eq_files(project_dir)\n\n    if not apr_path or not apr_path.is_file():\n        print_error("APR file is required.")\n        sys.exit(1)\n\n    print_success(f"Frame selected: {frame_name}")\n    print_success(f"APR file: {apr_path}")\n\n    if eq_path:\n        print_success(f"EQ file: {eq_path}")\n    else:\n        print_info("EQ file not used/found.")\n\n    return apr_path, eq_path, frame_name\n\n\n# =============================================================================\n# STABILIZATION SITES DETECTION\n# =============================================================================\n\ndef detect_stab_sites(project_dir: Path, doys: List[str]) -> List[str]:\n    control = project_dir / "control"\n    per_day = []\n\n    if control.is_dir():\n        for doy in doys:\n            p = control / f"active_igs_sites_{doy}.txt"\n            if p.is_file():\n                sites = []\n                for line in read_text_safe(p).splitlines():\n                    line = line.strip()\n                    if not line or line.startswith("*") or line.startswith("#"):\n                        continue\n\n                    for token in line.split():\n                        token = token.upper()\n                        if re.match(r"^[A-Z0-9]{4}$", token):\n                            sites.append(token)\n\n                if sites:\n                    per_day.append(set(sites))\n\n    if per_day:\n        common = set.intersection(*per_day) if len(per_day) > 1 else per_day[0]\n        if len(common) >= 3:\n            return sorted(common)\n\n    sites_defaults = project_dir / "tables" / "sites.defaults"\n    if sites_defaults.is_file():\n        sites = []\n        for line in read_text_safe(sites_defaults).splitlines():\n            stripped = line.strip()\n            if not stripped or stripped.startswith("*") or stripped.startswith("#"):\n                continue\n\n            parts = stripped.split()\n            if not parts:\n                continue\n\n            # Skip x-disabled lines but do not skip real station XMIS.\n            if parts[0].lower() == "x":\n                continue\n\n            if len(parts) >= 3 and parts[2].lower() in ["ftprnx", "glreps"]:\n                site = parts[0].upper()\n                if re.match(r"^[A-Z0-9]{4}$", site) and site not in sites:\n                    sites.append(site)\n\n        if sites:\n            return sites\n\n    print_warning("No stabilization sites auto-detected. Please enter them.")\n    manual = ask_input(\n        "Stabilization sites (space-separated, 4-char codes)",\n        "BADG DAEJ DGAR DJIG IISC MAL2 NTUS POL2 REUN XMIS",\n    ).upper().strip()\n\n    return [s for s in manual.split() if re.match(r"^[A-Z0-9]{4}$", s)]\n\n\n# =============================================================================\n# FINAL RESULTS DASHBOARD\n# =============================================================================\n\ndef parse_pbo_coordinates_from_org(org_file: Path, local_stations: List[str]) -> List[Dict[str, object]]:\n    """\n    Parse final pbo. coordinate records from a GLOBK/GLORG .org file.\n\n    Expected useful line form:\n    pbo. SITE_GPS ... X Y Z sigX sigY sigZ ... | lat lon h ... | N E U sigN sigE sigU ...\n\n    Returns one row per requested local station found.\n    """\n    rows: List[Dict[str, object]] = []\n    wanted = {s.upper() for s in local_stations}\n    seen = set()\n\n    if not org_file.is_file():\n        return rows\n\n    for line in read_text_safe(org_file).splitlines():\n        if not line.startswith("pbo."):\n            continue\n\n        parts_pipe = line.split("|")\n        left = parts_pipe[0].split()\n        if len(left) < 12:\n            continue\n\n        station = left[1].upper()\n        station4 = station.replace("_GPS", "")\n\n        if station4 not in wanted or station4 in seen:\n            continue\n\n        # Left side usually ends with:\n        # X Y Z sigX sigY sigZ corrXY corrXZ corrYZ\n        try:\n            x = float(left[-9])\n            y = float(left[-8])\n            z = float(left[-7])\n            sig_x = float(left[-6])\n            sig_y = float(left[-5])\n            sig_z = float(left[-4])\n        except Exception:\n            x = y = z = sig_x = sig_y = sig_z = None\n\n        lat = lon = height = None\n        sig_h = None\n        if len(parts_pipe) >= 2:\n            middle = parts_pipe[1].split()\n            if len(middle) >= 3:\n                try:\n                    lat = float(middle[0])\n                    lon = float(middle[1])\n                    height = float(middle[2])\n                except Exception:\n                    pass\n            if len(middle) >= 6:\n                try:\n                    sig_h = float(middle[5])\n                except Exception:\n                    pass\n\n        north = east = up = sig_n = sig_e = sig_u = None\n        if len(parts_pipe) >= 3:\n            right = parts_pipe[2].split()\n            if len(right) >= 6:\n                try:\n                    north = float(right[0])\n                    east = float(right[1])\n                    up = float(right[2])\n                    sig_n = float(right[3])\n                    sig_e = float(right[4])\n                    sig_u = float(right[5])\n                except Exception:\n                    pass\n\n        rows.append({\n            "station": station,\n            "x_m": x,\n            "y_m": y,\n            "z_m": z,\n            "sig_x_m": sig_x,\n            "sig_y_m": sig_y,\n            "sig_z_m": sig_z,\n            "lat_deg": lat,\n            "lon_deg": lon,\n            "height_m": height,\n            "sig_height_m": sig_h,\n            "north_m": north,\n            "east_m": east,\n            "up_m": up,\n            "sig_n_m": sig_n,\n            "sig_e_m": sig_e,\n            "sig_u_m": sig_u,\n        })\n        seen.add(station4)\n\n    return rows\n\n\ndef extract_pos_statistics(org_file: Path) -> List[str]:\n    """Extract POS STATISTICS lines from .org file."""\n    if not org_file.is_file():\n        return []\n    return [line.strip() for line in read_text_safe(org_file).splitlines() if "POS STATISTICS" in line.upper()]\n\n\ndef extract_solution_summary(org_file: Path) -> List[str]:\n    """Extract a few key summary lines from .org file."""\n    if not org_file.is_file():\n        return []\n\n    keep = []\n    for line in read_text_safe(org_file).splitlines():\n        u = line.upper()\n        if (\n            "SOLUTION:" in u\n            or "BASELINE ENTRIES" in u\n            or "POS STATISTICS" in u\n            or "WRMS ENU" in u\n            or "NRMS ENU" in u\n        ):\n            keep.append(line.strip())\n\n    return keep[:50]\n\n\ndef write_coordinates_csv(rows: List[Dict[str, object]], out_csv: Path) -> None:\n    """Write coordinate rows to CSV without external dependencies."""\n    out_csv.parent.mkdir(parents=True, exist_ok=True)\n    headers = [\n        "station",\n        "x_m", "y_m", "z_m",\n        "sig_x_m", "sig_y_m", "sig_z_m",\n        "lat_deg", "lon_deg", "height_m", "sig_height_m",\n        "north_m", "east_m", "up_m",\n        "sig_n_m", "sig_e_m", "sig_u_m",\n    ]\n\n    with open(out_csv, "w", encoding="utf-8") as f:\n        f.write(",".join(headers) + "\\n")\n        for row in rows:\n            vals = []\n            for h in headers:\n                v = row.get(h)\n                if v is None:\n                    vals.append("")\n                elif isinstance(v, float):\n                    vals.append(f"{v:.12f}".rstrip("0").rstrip("."))\n                else:\n                    vals.append(str(v))\n            f.write(",".join(vals) + "\\n")\n\n\n# =============================================================================\n# USER-REQUESTED EPOCH COORDINATE OUTPUT\n# =============================================================================\n\ndef _is_leap_year(year: int) -> bool:\n    return year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)\n\n\ndef _decimal_year_from_date(d: date) -> float:\n    days = 366 if _is_leap_year(d.year) else 365\n    return d.year + ((d.timetuple().tm_yday - 1) / days)\n\n\ndef _date_from_year_doy(year: int, doy: int) -> date:\n    return date(year, 1, 1) + timedelta(days=doy - 1)\n\n\ndef _mid_solution_epoch_decimal(year: str, start_doy: str, end_doy: str) -> Tuple[float, str]:\n    """Use the middle of the processed GLOBK span as the coordinate reference epoch."""\n    y = int(year)\n    start = _date_from_year_doy(y, int(start_doy))\n    end = _date_from_year_doy(y, int(end_doy))\n    mid_dt = datetime.combine(start, datetime.min.time()) + (datetime.combine(end, datetime.min.time()) - datetime.combine(start, datetime.min.time())) / 2\n    mid_date = mid_dt.date()\n    return _decimal_year_from_date(mid_date), mid_date.isoformat()\n\n\ndef parse_user_epoch(text: str) -> Tuple[float, str, str]:\n    """\n    Parse user epoch/date.\n    Accepted examples:\n      2025-01-01, 01.01.2025, 01/01/2025, 2025/01/01, 2025.0\n    Returns decimal_year, label_for_file, display_label.\n    """\n    t = text.strip()\n    if not t:\n        raise ValueError("empty epoch")\n\n    # Decimal epoch such as 2025.0 or 2025.5000\n    if re.fullmatch(r"\\d{4}(?:\\.\\d+)?", t):\n        dec = float(t)\n        label = (f"{dec:.5f}").replace(".", "p")\n        return dec, f"epoch_{label}", f"decimal epoch {dec:.5f}"\n\n    formats = [\n        ("%Y-%m-%d", "ymd"),\n        ("%Y/%m/%d", "ymd"),\n        ("%d.%m.%Y", "dmy"),\n        ("%d/%m/%Y", "dmy"),\n        ("%d-%m-%Y", "dmy"),\n    ]\n    for fmt, _kind in formats:\n        try:\n            d = datetime.strptime(t, fmt).date()\n            dec = _decimal_year_from_date(d)\n            return dec, f"epoch_{d.strftime(\'%Y%m%d\')}", d.isoformat()\n        except ValueError:\n            pass\n\n    raise ValueError("Unsupported epoch format. Use YYYY-MM-DD, DD.MM.YYYY, DD/MM/YYYY, or decimal year like 2025.0")\n\n\ndef parse_apr_velocity_for_station(apr_path: Optional[Path], station: str) -> Tuple[Optional[Tuple[float, float, float]], str, Optional[float]]:\n    """\n    Parse ECEF velocity in m/year from APR line if present.\n    Common APR format: SITE X Y Z VX VY VZ EPOCH ...\n    """\n    if apr_path is None or not apr_path.is_file():\n        return None, "no APR file", None\n\n    wanted = station.upper().replace("_GPS", "")\n    wanted_tokens = {wanted, wanted + "_GPS"}\n    try:\n        with open(apr_path, "r", errors="ignore") as f:\n            for line in f:\n                parts = line.split()\n                if len(parts) < 7:\n                    continue\n                name = parts[0].upper()\n                if name not in wanted_tokens:\n                    continue\n                try:\n                    vx = float(parts[4])\n                    vy = float(parts[5])\n                    vz = float(parts[6])\n                    epoch0 = None\n                    if len(parts) >= 8:\n                        try:\n                            epoch0 = float(parts[7])\n                        except Exception:\n                            epoch0 = None\n                    return (vx, vy, vz), f"APR velocity from {apr_path.name}", epoch0\n                except Exception:\n                    return None, f"APR line found but velocity unreadable in {apr_path.name}", None\n    except Exception as e:\n        return None, f"APR read error: {e}", None\n\n    return None, f"no velocity line for {wanted}_GPS in {apr_path.name}", None\n\n\ndef ecef_to_geodetic_wgs84(x: float, y: float, z: float) -> Tuple[float, float, float]:\n    """Convert ECEF XYZ in meters to WGS84 geodetic latitude, longitude, height."""\n    import math\n    a = 6378137.0\n    f = 1.0 / 298.257223563\n    e2 = f * (2.0 - f)\n    b = a * (1.0 - f)\n    ep2 = (a * a - b * b) / (b * b)\n\n    p = math.hypot(x, y)\n    if p == 0:\n        lon = 0.0\n    else:\n        lon = math.atan2(y, x)\n\n    theta = math.atan2(z * a, p * b)\n    sin_t = math.sin(theta)\n    cos_t = math.cos(theta)\n    lat = math.atan2(z + ep2 * b * sin_t**3, p - e2 * a * cos_t**3)\n\n    for _ in range(5):\n        sin_lat = math.sin(lat)\n        n = a / math.sqrt(1.0 - e2 * sin_lat * sin_lat)\n        h = p / math.cos(lat) - n\n        lat_new = math.atan2(z, p * (1.0 - e2 * n / (n + h)))\n        if abs(lat_new - lat) < 1e-14:\n            lat = lat_new\n            break\n        lat = lat_new\n\n    sin_lat = math.sin(lat)\n    n = a / math.sqrt(1.0 - e2 * sin_lat * sin_lat)\n    h = p / math.cos(lat) - n\n    return math.degrees(lat), math.degrees(lon), h\n\n\ndef write_epoch_coordinates_csv(rows: List[Dict[str, object]], out_csv: Path) -> None:\n    headers = [\n        "station", "target_epoch", "target_label", "reference_epoch", "reference_label", "delta_years",\n        "x_ref_m", "y_ref_m", "z_ref_m",\n        "vx_m_per_yr", "vy_m_per_yr", "vz_m_per_yr", "velocity_source", "apr_velocity_epoch",\n        "x_epoch_m", "y_epoch_m", "z_epoch_m", "lat_epoch_deg", "lon_epoch_deg", "height_epoch_m",\n        "note",\n    ]\n    out_csv.parent.mkdir(parents=True, exist_ok=True)\n    with open(out_csv, "w", encoding="utf-8") as f:\n        f.write(",".join(headers) + "\\n")\n        for row in rows:\n            vals = []\n            for h in headers:\n                v = row.get(h)\n                if v is None:\n                    vals.append("")\n                elif isinstance(v, float):\n                    vals.append(f"{v:.12f}".rstrip("0").rstrip("."))\n                else:\n                    vals.append(str(v).replace(",", ";"))\n            f.write(",".join(vals) + "\\n")\n\n\ndef print_epoch_coordinate_table(rows: List[Dict[str, object]], target_display: str) -> None:\n    print_header(f"LOCAL COORDINATES AT REQUESTED EPOCH: {target_display}")\n    if not rows:\n        print_warning("No epoch coordinates could be created.")\n        return\n\n    print("Station       X_epoch(m)        Y_epoch(m)        Z_epoch(m)        Lat(deg)        Lon(deg)        H(m)        Velocity")\n    print("-" * 126)\n    for r in rows:\n        vel_note = "APR" if str(r.get("velocity_source", "")).startswith("APR velocity") else "ZERO/UNKNOWN"\n        print(\n            f"{str(r.get(\'station\',\'\')):10s} "\n            f"{float(r.get(\'x_epoch_m\', 0.0)):16.4f} "\n            f"{float(r.get(\'y_epoch_m\', 0.0)):16.4f} "\n            f"{float(r.get(\'z_epoch_m\', 0.0)):16.4f} "\n            f"{float(r.get(\'lat_epoch_deg\', 0.0)):14.10f} "\n            f"{float(r.get(\'lon_epoch_deg\', 0.0)):14.10f} "\n            f"{float(r.get(\'height_epoch_m\', 0.0)):11.4f} "\n            f"{vel_note}"\n        )\n\n\ndef create_epoch_coordinate_output(\n    coord_rows: List[Dict[str, object]],\n    apr_path: Optional[Path],\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    out_dir: Path,\n) -> None:\n    """\n    Create local coordinates at a user-specified epoch/date.\n\n    Important geodetic note:\n    A coordinate can only be moved from one epoch to another if velocity is known.\n    This tool uses ECEF velocities from the selected APR file when available.\n    If a local station has no velocity in the APR, zero velocity is assumed and a warning is written.\n    """\n    if not coord_rows:\n        print_warning("No final coordinates available for epoch propagation.")\n        return\n\n    print_header("OPTIONAL COORDINATES AT USER-SPECIFIED EPOCH")\n    print_info("Accepted date formats: 2025-01-01, 01.01.2025, 01/01/2025, or decimal epoch 2025.0")\n    print_warning("Epoch propagation needs station velocity. If local velocity is missing in APR, zero velocity will be assumed and reported.")\n\n    default_epoch = "2025-01-01"\n    while True:\n        text = ask_input("Target epoch/date for coordinates", default_epoch)\n        try:\n            target_epoch, target_label, target_display = parse_user_epoch(text)\n            break\n        except ValueError as e:\n            print_error(str(e))\n\n    ref_epoch, ref_label = _mid_solution_epoch_decimal(year, start_doy, end_doy)\n    dt = target_epoch - ref_epoch\n\n    print_info(f"Reference coordinate epoch used: {ref_epoch:.6f} ({ref_label}, middle of selected GLOBK span)")\n    print_info(f"Target coordinate epoch        : {target_epoch:.6f} ({target_display})")\n    print_info(f"Delta years                    : {dt:.6f}")\n    if apr_path:\n        print_info(f"Velocity source APR            : {apr_path}")\n\n    epoch_rows: List[Dict[str, object]] = []\n    zero_velocity_stations: List[str] = []\n\n    for r in coord_rows:\n        station_full = str(r.get("station", "")).upper()\n        station4 = station_full.replace("_GPS", "")[:4]\n        try:\n            x0 = float(r.get("x_m"))\n            y0 = float(r.get("y_m"))\n            z0 = float(r.get("z_m"))\n        except Exception:\n            print_warning(f"Skipping {station_full}: missing XYZ in combined .org")\n            continue\n\n        vel, source, apr_vel_epoch = parse_apr_velocity_for_station(apr_path, station4)\n        note = ""\n        if vel is None:\n            vx = vy = vz = 0.0\n            note = "No APR velocity found; zero velocity assumed"\n            zero_velocity_stations.append(station4)\n        else:\n            vx, vy, vz = vel\n            if abs(vx) < 1e-12 and abs(vy) < 1e-12 and abs(vz) < 1e-12:\n                note = "APR velocity is zero; coordinate unchanged by epoch propagation"\n                zero_velocity_stations.append(station4)\n            else:\n                note = "Propagated using APR ECEF velocity"\n\n        x1 = x0 + vx * dt\n        y1 = y0 + vy * dt\n        z1 = z0 + vz * dt\n        lat, lon, h = ecef_to_geodetic_wgs84(x1, y1, z1)\n\n        epoch_rows.append({\n            "station": station_full,\n            "target_epoch": target_epoch,\n            "target_label": target_display,\n            "reference_epoch": ref_epoch,\n            "reference_label": ref_label,\n            "delta_years": dt,\n            "x_ref_m": x0,\n            "y_ref_m": y0,\n            "z_ref_m": z0,\n            "vx_m_per_yr": vx,\n            "vy_m_per_yr": vy,\n            "vz_m_per_yr": vz,\n            "velocity_source": source,\n            "apr_velocity_epoch": apr_vel_epoch,\n            "x_epoch_m": x1,\n            "y_epoch_m": y1,\n            "z_epoch_m": z1,\n            "lat_epoch_deg": lat,\n            "lon_epoch_deg": lon,\n            "height_epoch_m": h,\n            "note": note,\n        })\n\n    print_epoch_coordinate_table(epoch_rows, target_display)\n\n    out_csv = out_dir / f"local_coordinates_{target_label}.csv"\n    out_txt = out_dir / f"local_coordinates_{target_label}_notes.txt"\n    write_epoch_coordinates_csv(epoch_rows, out_csv)\n    out_txt.write_text(\n        "LOCAL COORDINATES AT USER-SPECIFIED EPOCH\\n"\n        f"Target epoch/date       : {target_display}\\n"\n        f"Target decimal epoch    : {target_epoch:.8f}\\n"\n        f"Reference decimal epoch : {ref_epoch:.8f}\\n"\n        f"Reference date          : {ref_label}\\n"\n        f"Delta years             : {dt:.8f}\\n"\n        f"Velocity APR            : {apr_path if apr_path else \'Not found\'}\\n"\n        "Method                  : XYZ_epoch = XYZ_reference + Vxyz * delta_years\\n"\n        "Note                    : If local station velocity is missing/zero, coordinate is not truly epoch-transformed.\\n"\n        f"Zero/missing velocity stations: {\' \'.join(sorted(set(zero_velocity_stations))) if zero_velocity_stations else \'None\'}\\n",\n        encoding="utf-8",\n    )\n    print_success(f"Saved requested-epoch coordinate CSV: {out_csv}")\n    print_success(f"Saved requested-epoch notes: {out_txt}")\n\n    if zero_velocity_stations:\n        print_warning("Some local stations had zero/missing velocity: " + " ".join(sorted(set(zero_velocity_stations))))\n        print_warning("For precise epoch transformation, add real station velocities in the APR/VEL file or process a long time span to estimate velocities.")\n\n\ndef print_coordinate_table(rows: List[Dict[str, object]]) -> None:\n    """Print final coordinate table on screen."""\n    if not rows:\n        print_warning("No local station pbo. coordinate rows found in combined .org.")\n        return\n\n    print_header("FINAL LOCAL STATION COORDINATES FROM COMBINED .org")\n    print("Station       Latitude(deg)     Longitude(deg)      Height(m)          X(m)              Y(m)              Z(m)")\n    print("-" * 118)\n\n    for r in rows:\n        def fmt(value: object, width: int, decimals: int = 5) -> str:\n            if value is None:\n                return " " * (width - 3) + "NA "\n            if isinstance(value, float):\n                return f"{value:{width}.{decimals}f}"\n            return f"{str(value):>{width}}"\n\n        print(\n            f"{str(r[\'station\']):10s} "\n            f"{fmt(r.get(\'lat_deg\'), 16, 10)} "\n            f"{fmt(r.get(\'lon_deg\'), 16, 10)} "\n            f"{fmt(r.get(\'height_m\'), 12, 4)} "\n            f"{fmt(r.get(\'x_m\'), 16, 4)} "\n            f"{fmt(r.get(\'y_m\'), 16, 4)} "\n            f"{fmt(r.get(\'z_m\'), 16, 4)}"\n        )\n\n\ndef print_uncertainty_table(rows: List[Dict[str, object]]) -> None:\n    """Print uncertainty table on screen."""\n    if not rows:\n        return\n\n    print_header("LOCAL STATION UNCERTAINTIES")\n    print("Station       sigX(m)    sigY(m)    sigZ(m)    sigN(m)    sigE(m)    sigU(m)")\n    print("-" * 84)\n\n    for r in rows:\n        def fmt(value: object) -> str:\n            if value is None:\n                return "      NA "\n            if isinstance(value, float):\n                return f"{value:9.5f}"\n            return f"{str(value):>9s}"\n\n        print(\n            f"{str(r[\'station\']):10s} "\n            f"{fmt(r.get(\'sig_x_m\'))} "\n            f"{fmt(r.get(\'sig_y_m\'))} "\n            f"{fmt(r.get(\'sig_z_m\'))} "\n            f"{fmt(r.get(\'sig_n_m\'))} "\n            f"{fmt(r.get(\'sig_e_m\'))} "\n            f"{fmt(r.get(\'sig_u_m\'))}"\n        )\n\n\ndef make_persistent_pos_files(project_dir: Path, daily_org_files: List[Path], log_dir: Path) -> Optional[Path]:\n    """\n    Create persistent .pos files using tssum, following the tutorial idea:\n    tssum pos pbo.final_frame gsoln/*org\n\n    If tssum is unavailable or fails, this returns None but does not stop the script.\n    """\n    if not daily_org_files:\n        return None\n\n    if not command_exists("tssum"):\n        print_warning("tssum not found; cannot create persistent .pos files.")\n        return None\n\n    gsoln = project_dir / "gsoln"\n    pos_dir = gsoln / "pos_final"\n    pos_dir.mkdir(exist_ok=True)\n\n    cmd = ["tssum", str(pos_dir), "pbo.final_frame"] + [str(p) for p in daily_org_files]\n    log_path = log_dir / "tssum_pos_final.log"\n\n    print_progress("Creating persistent .pos files with tssum")\n    print_info("Running: " + " ".join(shell_quote(x) for x in cmd))\n\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.run(\n                cmd,\n                cwd=str(gsoln),\n                stdout=f,\n                stderr=subprocess.STDOUT,\n                text=True,\n                timeout=300,\n            )\n\n        if proc.returncode == 0:\n            print_success(f"Persistent .pos files saved in: {pos_dir}")\n            return pos_dir\n\n        print_warning(f"tssum returned {proc.returncode}. Check: {log_path}")\n        return None\n\n    except Exception as e:\n        print_warning(f"Could not run tssum: {e}")\n        return None\n\n\ndef find_result_plots(project_dir: Path, year: str, start_doy: str, end_doy: str, local_stations: List[str]) -> Dict[str, List[Path]]:\n    """Find result plots generated by sh_plot_pos."""\n    gsoln = project_dir / "gsoln"\n\n    plot_dirs = sorted(gsoln.glob(f"plots_{year}-{start_doy}_{year}-{end_doy}"))\n    if not plot_dirs:\n        plot_dirs = sorted(gsoln.glob("plots_*"))\n\n    plot_files: List[Path] = []\n    for d in plot_dirs:\n        plot_files.extend(sorted(d.glob("*.ps")))\n\n    local_upper = {s.upper() for s in local_stations}\n\n    local_plots = []\n    other_plots = []\n\n    for p in plot_files:\n        stem_up = p.name.upper()\n        if any(st in stem_up for st in local_upper):\n            local_plots.append(p)\n        else:\n            other_plots.append(p)\n\n    # Histogram plots may be in gsoln itself.\n    hist_plots = sorted(gsoln.glob("pshist_*.sum")) + sorted(gsoln.glob("pshist_*.ps"))\n\n    return {\n        "local_plots": local_plots,\n        "other_plots": other_plots,\n        "hist_plots": hist_plots,\n    }\n\n\ndef convert_ps_to_png(ps_file: Path, png_file: Path) -> bool:\n    """Convert PS to PNG using ghostscript if available."""\n    if not command_exists("gs"):\n        return False\n\n    png_file.parent.mkdir(parents=True, exist_ok=True)\n\n    cmd = [\n        "gs",\n        "-dSAFER",\n        "-dBATCH",\n        "-dNOPAUSE",\n        "-sDEVICE=png16m",\n        "-r130",\n        f"-sOutputFile={png_file}",\n        str(ps_file),\n    ]\n\n    try:\n        proc = subprocess.run(cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, text=True, timeout=120)\n        return proc.returncode == 0 and png_file.is_file() and png_file.stat().st_size > 0\n    except Exception:\n        return False\n\n\ndef open_files_with_viewer(files: List[Path]) -> None:\n    """Open files in GUI if possible."""\n    opener = shutil.which("xdg-open")\n    if not opener:\n        print_warning("xdg-open not found. Cannot auto-open plots.")\n        return\n\n    for p in files:\n        try:\n            subprocess.Popen([opener, str(p)], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)\n        except Exception as e:\n            print_warning(f"Could not open {p.name}: {e}")\n\n\ndef print_plot_summary_and_optionally_open(\n    project_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    local_stations: List[str],\n) -> None:\n    """List plot files and optionally open/convert them."""\n    plots = find_result_plots(project_dir, year, start_doy, end_doy, local_stations)\n\n    local_plots = plots["local_plots"]\n    hist_plots = plots["hist_plots"]\n    other_plots = plots["other_plots"]\n\n    print_header("RESULT GRAPHS / PLOTS")\n    print_info("GAMIT/GLOBK plots are normally PostScript files (.ps).")\n    print_info("They cannot be drawn inside a plain terminal, but this script can list/open them.")\n\n    if hist_plots:\n        print_success("Histogram/statistic plots:")\n        for p in hist_plots[:20]:\n            print(f"  {p}")\n\n    if local_plots:\n        print_success("Local station residual plots:")\n        for p in local_plots:\n            print(f"  {p}")\n\n    if other_plots:\n        print_info(f"Other station plots available: {len(other_plots)} file(s).")\n\n    if not local_plots and not hist_plots and not other_plots:\n        print_warning("No plot files found.")\n        return\n\n    if ask_yes_no("Open local station plots on screen now? Requires GUI", "no"):\n        files_to_open = local_plots[:10]\n        if not files_to_open:\n            files_to_open = (hist_plots + other_plots)[:10]\n\n        # Prefer direct opening. If PS viewer is not configured, create PNG copies.\n        print_info("Trying to open plot files with xdg-open.")\n        open_files_with_viewer(files_to_open)\n\n    if ask_yes_no("Convert local station plots to PNG for easier viewing?", "no"):\n        out_dir = project_dir / "gsoln" / "final_outputs" / "plots_png"\n        converted = []\n        source_plots = local_plots[:20] if local_plots else (hist_plots + other_plots)[:20]\n\n        for ps in source_plots:\n            png = out_dir / (ps.stem + ".png")\n            if convert_ps_to_png(ps, png):\n                converted.append(png)\n\n        if converted:\n            print_success(f"Converted {len(converted)} plot(s) to PNG:")\n            for p in converted:\n                print(f"  {p}")\n\n            if ask_yes_no("Open converted PNG plots now?", "no"):\n                open_files_with_viewer(converted[:10])\n        else:\n            print_warning("No plots converted. Install/check Ghostscript: sudo apt install ghostscript")\n\n\ndef print_final_results_dashboard(\n    project_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    yy: str,\n    local_stations: List[str],\n    daily_org_files: List[Path],\n    comb_org: List[Path],\n    log_dir: Path,\n    apr_path: Optional[Path] = None,\n    frame_name: str = "",\n) -> None:\n    """Print all important results at the end."""\n    print_header("FINAL RESULTS DASHBOARD")\n\n    gsoln = project_dir / "gsoln"\n    out_dir = gsoln / "final_outputs"\n    out_dir.mkdir(parents=True, exist_ok=True)\n\n    print_info(f"Project       : {project_dir}")\n    print_info(f"GLOBK folder  : {gsoln}")\n    print_info(f"Daily .org    : {len(daily_org_files)} file(s)")\n    for p in daily_org_files:\n        print(f"  {p.name}")\n\n    combined = comb_org[0] if comb_org else None\n    if combined:\n        print_success(f"Combined .org : {combined.name}")\n    else:\n        print_warning("No combined .org file found.")\n\n    if combined:\n        summary_lines = extract_solution_summary(combined)\n        if summary_lines:\n            print_header("COMBINED .org SOLUTION SUMMARY")\n            for line in summary_lines:\n                print(line)\n\n        pos_stats = extract_pos_statistics(combined)\n        if pos_stats:\n            print_header("POS STATISTICS")\n            for line in pos_stats:\n                print(line)\n\n            stats_file = out_dir / "pos_statistics.txt"\n            stats_file.write_text("\\n".join(pos_stats) + "\\n", encoding="utf-8")\n            print_success(f"Saved POS statistics: {stats_file}")\n\n        coord_rows = parse_pbo_coordinates_from_org(combined, local_stations)\n        print_coordinate_table(coord_rows)\n        print_uncertainty_table(coord_rows)\n\n        if coord_rows:\n            csv_file = out_dir / "local_final_coordinates.csv"\n            write_coordinates_csv(coord_rows, csv_file)\n            print_success(f"Saved coordinate CSV: {csv_file}")\n\n            txt_file = out_dir / "extract_final_coordinates_command.txt"\n            local_pattern = "\\\\|".join(st.upper() for st in local_stations)\n            txt_file.write_text(\n                f"cd {shell_quote(gsoln)}\\n"\n                f"grep \'^pbo.\' {shell_quote(combined.name)} | grep -i \\"{local_pattern}\\"\\n",\n                encoding="utf-8",\n            )\n            print_success(f"Saved extraction command: {txt_file}")\n\n            if ask_yes_no("Create local coordinates at a user-specified epoch/date?", "yes"):\n                create_epoch_coordinate_output(coord_rows, apr_path, year, start_doy, end_doy, out_dir)\n\n    # Try making persistent .pos time-series files.\n    pos_dir = make_persistent_pos_files(project_dir, daily_org_files, log_dir)\n    if pos_dir:\n        pos_files = sorted(pos_dir.glob("*.pos"))\n        print_header("PERSISTENT TIME-SERIES .pos FILES")\n        print_success(f"Created/found {len(pos_files)} .pos file(s) in {pos_dir}")\n        for p in pos_files[:40]:\n            print(f"  {p.name}")\n        if len(pos_files) > 40:\n            print(f"  ... {len(pos_files) - 40} more")\n\n    # Plot listing/opening/conversion.\n    print_plot_summary_and_optionally_open(project_dir, year, start_doy, end_doy, local_stations)\n\n    print_header("USEFUL FINAL COMMANDS")\n    if combined:\n        local_pattern = "\\\\|".join(st.upper() for st in local_stations)\n        print("Extract local final coordinates:")\n        print(f"  cd {shell_quote(gsoln)}")\n        print(f"  grep \'^pbo.\' {shell_quote(combined.name)} | grep -i \\"{local_pattern}\\"")\n    print()\n    print("List all .org outputs:")\n    print(f"  ls -lh {shell_quote(gsoln)}/*.org")\n    print()\n    print("List all plots:")\n    print(f"  find {shell_quote(gsoln)} -type f \\\\( -name \'*.ps\' -o -name \'*.png\' \\\\)")\n\n\n# =============================================================================\n# MAIN\n# =============================================================================\n\ndef main() -> int:\n    print_header("AUTOM-GLOBK / GLORG DASHBOARD")\n\n    default_project = os.environ.get("INTEGRATED_PROJECT_DIR", str(Path.cwd()))\n    project_dir = normalize_path(ask_input("Project folder", default_project))\n\n    if not project_dir.is_dir():\n        print_error(f"Not a directory: {project_dir}")\n        return 1\n\n    print_success(f"Project: {project_dir}")\n\n    scan_results = scan_hfiles(project_dir)\n    if not scan_results:\n        print_error("No h-files found. Run GAMIT first.")\n        return 1\n\n    selected = select_processing_range(scan_results)\n\n    if not check_scan_consistency(selected):\n        return 1\n\n    year, start_doy, end_doy, ndays_str, expt, netext, doys = detect_settings(selected)\n    ndays = int(ndays_str)\n    yy = selected[doys[0]]["yy"]\n\n    show_detected_settings(year, start_doy, end_doy, ndays_str, expt, netext, doys)\n\n    if not ask_yes_no("Proceed?", "yes"):\n        return 0\n\n    log_dir = project_dir / "globk_glorg_logs"\n    log_dir.mkdir(exist_ok=True)\n\n    print_header("TOOL CHECK")\n    required = ["sh_glred", "globk", "glorg", "htoglb"]\n    missing = False\n\n    for cmd in required:\n        if not command_exists(cmd):\n            print_error(f"{cmd} not found")\n            missing = True\n        else:\n            print_success(f"{cmd} found at {shutil.which(cmd)}")\n\n    if missing:\n        print_error("Missing required tools. Source GAMIT/GLOBK environment.")\n        return 1\n\n    print_header("COMMAND FILE VERSION CHECK")\n    glorg_cmd = project_dir / "tables" / "glorg.cmd"\n    need_regenerate = False\n\n    if glorg_cmd.is_file():\n        header = read_text_safe(glorg_cmd, max_bytes=300)\n        if not re.search(r"version\\s+[0-9.]+", header, re.I):\n            need_regenerate = True\n            print_warning("glorg.cmd has no clear version header.")\n    else:\n        need_regenerate = True\n\n    if need_regenerate:\n        if not regenerate_command_files(project_dir):\n            print_error("Could not regenerate command files. Exiting.")\n            return 1\n    else:\n        print_success("Command files appear to have a version header.")\n\n    print_header("LOCAL STATION DETECTION")\n    local_stations: List[str] = []\n    sites_defaults = project_dir / "tables" / "sites.defaults"\n\n    if sites_defaults.is_file():\n        for line in read_text_safe(sites_defaults).splitlines():\n            if "localrx" in line.lower():\n                parts = line.split()\n                if parts:\n                    site = parts[0].lower().replace("_gps", "")\n                    if re.match(r"^[a-z0-9]{4}$", site) and site not in local_stations:\n                        local_stations.append(site)\n\n    if not local_stations:\n        user_input = ask_input(\n            "Enter local station names (space-separated, 4-char codes)",\n            "hyd2 indo jaba jaip mndi rai3 roo3",\n        )\n        local_stations = [s.lower() for s in user_input.split() if re.match(r"^[a-z0-9]{4}$", s.lower())]\n\n    print_success("Local stations: " + " ".join(local_stations))\n\n    print_header("APR SELECTION / CHECK / REPAIR")\n    if not ensure_custom_apr_exists(project_dir):\n        return 1\n\n    apr_path, eq_path, frame_name = select_frame(project_dir)\n\n    print_success(f"Selected APR for GLOBK: {apr_path}")\n    print_success(f"Detected APR family   : {frame_name}")\n\n    if not ensure_local_stations_in_apr(apr_path, project_dir, local_stations):\n        print_error("APR repair failed.")\n        return 1\n\n    fix_zero_sigmas_in_apr(apr_path, local_stations)\n\n    check_sites_exist_in_apr(apr_path, local_stations, "local stations")\n\n    stab_sites = detect_stab_sites(project_dir, doys)\n\n    if len(stab_sites) < 3:\n        print_error("Need at least 3 stabilization sites.")\n        return 1\n\n    print_success(f"Stabilization sites: {\' \'.join(stab_sites)}")\n\n    if len(stab_sites) < 8:\n        print_warning("Only a few stabilization sites; 8-10 recommended for robustness.")\n\n    print_header("PATCHING COMMAND FILES")\n    print_info("Will patch globk.cmd and glorg.cmd with:")\n    print(f"  APR: {apr_path}")\n    if eq_path:\n        print(f"  EQ:  {eq_path}")\n    print(f"  Stabilization: {\' \'.join(stab_sites)}")\n\n    if ask_yes_no("Proceed with patching?", "yes"):\n        patch_globk_glorg(project_dir, apr_path, eq_path, stab_sites)\n    else:\n        print_warning("Skipping patching. Using existing command files.")\n        if not ask_yes_no("Continue with existing command files?", "no"):\n            return 0\n\n    print_header("RUNNING sh_glred (NORMAL H G T)")\n    if ask_yes_no("Run htoglb (H) as well? Choose yes for fresh processing", "yes"):\n        options = "H G T"\n    else:\n        options = "G T"\n\n    rc = run_sh_glred(project_dir, year, start_doy, end_doy, expt, netext, options, log_dir)\n    if rc != 0:\n        print_warning(f"sh_glred returned code {rc}. Check logs.")\n\n    print_header("VERIFYING DAILY .org FILES")\n    org_files = verify_org_files(project_dir, expt, yy, doys)\n\n    if org_files:\n        print_success(f"Found {len(org_files)} daily .org files.")\n        for f in org_files:\n            print(f"  {f.name}")\n    else:\n        print_warning("No daily .org files found.")\n        print_info("Check sh_glred log and gsoln/*.prt/*.log files.")\n        if not ask_yes_no("Continue anyway?", "no"):\n            return 1\n\n    print_header("OPTIONAL COMBINED SURVEY")\n    # FIX 1: initialize comb_org before use\n    comb_org: List[Path] = find_combined_org(project_dir, expt, yy, start_doy, end_doy)\n\n    if comb_org:\n        print_info(f"Existing combined .org found: {comb_org[0].name}")\n\n    if ndays > 1 and org_files:\n        if ask_yes_no("Run/re-run combined survey with COMB + -ncomb?", "yes"):\n            rc_comb = run_combined_survey(project_dir, year, start_doy, end_doy, expt, netext, ndays, log_dir)\n            if rc_comb == 0:\n                print_success("Combined survey completed.")\n                comb_org = find_combined_org(project_dir, expt, yy, start_doy, end_doy)\n                if comb_org:\n                    print_success(f"Combined .org file created: {comb_org[0].name}")\n                else:\n                    print_warning("Combined .org file not found.")\n            else:\n                print_warning(f"Combined survey returned {rc_comb}.")\n\n    print_final_results_dashboard(\n        project_dir=project_dir,\n        year=year,\n        start_doy=start_doy,\n        end_doy=end_doy,\n        expt=expt,\n        yy=yy,\n        local_stations=local_stations,\n        daily_org_files=org_files,\n        comb_org=comb_org,\n        log_dir=log_dir,\n        apr_path=apr_path,\n        frame_name=frame_name,\n    )\n\n    print_header("FINISHED")\n    print_info("Important results were printed above.")\n    print_info("Final coordinates are in the combined .org file and CSV if extraction succeeded.")\n    print_info("Do NOT run glorg manually on the .org file.")\n    print_success(f"Logs saved in: {log_dir}")\n    return 0\n\n\nif __name__ == "__main__":\n    try:\n        sys.exit(main())\n    except KeyboardInterrupt:\n        print("\\nUser stopped.")\n        sys.exit(130)'



class Colors:
    RED = "\033[91m"
    GREEN = "\033[92m"
    YELLOW = "\033[93m"
    BLUE = "\033[94m"
    CYAN = "\033[96m"
    BOLD = "\033[1m"
    END = "\033[0m"


def ctext(text: str, color: str) -> str:
    return f"{color}{text}{Colors.END}"


def print_header(text: str) -> None:
    print()
    print(ctext("=" * 90, Colors.CYAN))
    print(ctext(f"{text:^90}", Colors.CYAN + Colors.BOLD))
    print(ctext("=" * 90, Colors.CYAN))


def ask_choice() -> int:
    print_header("AUTOM-GAMIT + GLOBK/GLORG INTEGRATED MENU")
    print("1. Run GAMIT only")
    print("2. Run GLOBK/GLORG only")
    print("3. Run full GAMIT first, then GLOBK/GLORG dashboard")
    print()
    while True:
        ans = input(ctext("Enter choice (1-3) [3]: ", Colors.CYAN)).strip()
        if ans == "":
            return 3
        if ans in ("1", "2", "3"):
            return int(ans)
        print("Please enter 1, 2, or 3.")


def ask_yes_no(question: str, default: str = "yes") -> bool:
    prompt = "[Y/n]" if default.lower() == "yes" else "[y/N]"
    while True:
        ans = input(ctext(f"{question} {prompt}: ", Colors.CYAN)).strip().lower()
        if ans == "":
            return default.lower() == "yes"
        if ans in ("y", "yes"):
            return True
        if ans in ("n", "no"):
            return False
        print("Please answer yes or no.")


def _load_part(source: str, module_name: str, file_label: str) -> dict:
    ns = {"__name__": module_name, "__file__": file_label}
    exec(compile(source, file_label, "exec"), ns)
    return ns


def _run_part(source: str, module_name: str, file_label: str) -> int:
    try:
        ns = _load_part(source, module_name, file_label)
        main_func = ns.get("main")
        if main_func is None:
            print(ctext(f"ERROR: main() not found in {file_label}", Colors.RED))
            return 1
        result = main_func()
        if result is None:
            return 0
        return int(result)
    except SystemExit as e:
        if e.code is None:
            return 0
        try:
            return int(e.code)
        except Exception:
            return 1
    except KeyboardInterrupt:
        print("\nUser stopped the program.")
        return 130
    except Exception:
        print(ctext("ERROR: Unexpected error while running integrated part.", Colors.RED))
        traceback.print_exc()
        return 1


def run_gamit() -> int:
    print_header("STARTING PART 1: GAMIT")
    return _run_part(GAMIT_SOURCE, "__integrated_gamit_part__", "integrated_gamit_part.py")


def run_globk() -> int:
    print_header("STARTING PART 2: GLOBK/GLORG DASHBOARD")
    return _run_part(GLOBK_SOURCE, "__integrated_globk_part__", "integrated_globk_part.py")


def main() -> int:
    choice = ask_choice()

    if choice == 1:
        return run_gamit()

    if choice == 2:
        return run_globk()

    gamit_rc = run_gamit()
    if gamit_rc != 0:
        print(ctext(f"GAMIT part ended with return code {gamit_rc}.", Colors.YELLOW))
        if not ask_yes_no("Run GLOBK/GLORG anyway?", "no"):
            return gamit_rc

    print()
    print(ctext("GAMIT part finished. Now starting GLOBK/GLORG dashboard.", Colors.GREEN))
    print(ctext("The same project folder will be offered as default when available.", Colors.BLUE))
    return run_globk()


if __name__ == "__main__":
    sys.exit(main())
